{
  "name": "Order Management & Verification System",
  "description": "A modern, professional React dashboard for managing customer service orders and verification workflows, featuring advanced filtering and real-time status updates."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type OrderStatus = 'Chờ xử lý' | 'Đang thực hiện' | 'Hoàn thành' | 'Đã hủy' | 'Quá thời gian';
export type VerificationStatus = 'Chờ xác minh' | 'Đã xác minh' | 'Không đạt' | 'Tất cả';

export interface Order {
  id: string;
  orderCode: string;
  service: string[];
  quantity: number;
  price: number;
  requestStatus: string;
  orderStatus: OrderStatus;
  verificationStatus: VerificationStatus;
  customer: {
    name: string;
    phone: string;
  };
  vehicle: {
    plate: string;
    brand: string;
    model: string;
  };
  address: string;
  createdAt: string;
  isPortal?: boolean;
  isEcom?: boolean;
}

export interface FilterState {
  orderCode: string;
  phone: string;
  plate: string;
  service: string;
  partner: string;
  verificationStatus: VerificationStatus;
  fromDate: string;
  toDate: string;
}

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import FilterPanel from './components/FilterPanel';
import OrderTable from './components/OrderTable';
import VerifyModal from './components/VerifyModal';
import { Order, FilterState, VerificationStatus } from './types';
import { MOCK_ORDERS } from './constants';

const App: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);
  const [filteredOrders, setFilteredOrders] = useState<Order[]>(MOCK_ORDERS);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);

  const [filters, setFilters] = useState<FilterState>({
    orderCode: '',
    phone: '',
    plate: '',
    service: 'Tất cả',
    partner: 'Tất cả',
    verificationStatus: 'Tất cả',
    fromDate: '2024-02-01',
    toDate: '2024-02-28',
  });

  const handleFilterChange = (key: keyof FilterState, value: string) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  const applyFilters = () => {
    let result = [...orders];

    if (filters.orderCode) {
      result = result.filter(o => o.orderCode.toLowerCase().includes(filters.orderCode.toLowerCase()));
    }
    if (filters.phone) {
      result = result.filter(o => o.customer.phone.includes(filters.phone));
    }
    if (filters.plate) {
      result = result.filter(o => o.vehicle.plate.toLowerCase().includes(filters.plate.toLowerCase()));
    }
    if (filters.verificationStatus !== 'Tất cả') {
      result = result.filter(o => o.verificationStatus === filters.verificationStatus);
    }

    setFilteredOrders(result);
  };

  const handleVerify = (orderId: string, status: VerificationStatus) => {
    const updatedOrders = orders.map(o => 
      o.id === orderId ? { ...o, verificationStatus: status } : o
    );
    setOrders(updatedOrders);
    setSelectedOrder(null);
  };

  useEffect(() => {
    applyFilters();
  }, [filters, orders]);

  return (
    <div className="flex h-screen overflow-hidden bg-slate-50">
      <Sidebar isOpen={isSidebarOpen} toggle={() => setIsSidebarOpen(!isSidebarOpen)} />

      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header />

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 scrollbar-thin">
          <section>
            <FilterPanel 
              filters={filters} 
              onFilterChange={handleFilterChange} 
              onSearch={applyFilters}
            />
          </section>

          <section className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <h2 className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                <span className="w-2 h-2 bg-emerald-500 rounded-full"></span>
                Kết quả tìm kiếm
                <span className="ml-2 px-2 py-0.5 bg-slate-200 text-slate-600 rounded-full text-[10px] font-bold">
                  {filteredOrders.length}
                </span>
              </h2>
            </div>

            <OrderTable 
              orders={filteredOrders} 
              onVerifyClick={(order) => setSelectedOrder(order)} 
            />
          </section>
        </div>
      </main>

      {selectedOrder && (
        <VerifyModal 
          order={selectedOrder} 
          onClose={() => setSelectedOrder(null)}
          onConfirm={(status) => handleVerify(selectedOrder.id, status)}
        />
      )}
    </div>
  );
};

export default App;

