import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import FilterPanel from './components/FilterPanel';
import OrderTable from './components/OrderTable';
import VerifyModal from './components/VerifyModal';
import { Order, FilterState, VerificationStatus } from './types';
import { MOCK_ORDERS } from './constants';

const App: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);
  const [filteredOrders, setFilteredOrders] = useState<Order[]>(MOCK_ORDERS);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date().toLocaleString('vi-VN'));

  const [filters, setFilters] = useState<FilterState>({
    orderCode: '',
    phone: '',
    plate: '',
    service: 'Tất cả',
    partner: 'Tất cả',
    tollStation: 'Tất cả',
    orderStatus: 'Tất cả',
    requestStatus: 'Tất cả',
    verificationStatus: 'Tất cả',
    fromDate: '2026-02-01',
    toDate: '2026-02-28',
  });

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date().toLocaleString('vi-VN')), 1000);
    return () => clearInterval(timer);
  }, []);

  const handleFilterChange = (key: keyof FilterState, value: string) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  const applyFilters = () => {
    let result = [...orders];
    if (filters.verificationStatus !== 'Tất cả') {
      result = result.filter(o => o.verificationStatus === filters.verificationStatus);
    }
    setFilteredOrders(result);
  };

  const handleVerify = (orderId: string, status: VerificationStatus) => {
    const updatedOrders = orders.map(o => 
      o.id === orderId ? { ...o, verificationStatus: status } : o
    );
    setOrders(updatedOrders);
    setSelectedOrder(null);
  };

  useEffect(() => {
    applyFilters();
  }, [filters, orders]);

  return (
    <div className="flex h-screen overflow-hidden bg-[#f0f2f5]">
      <Sidebar isOpen={isSidebarOpen} toggle={() => setIsSidebarOpen(!isSidebarOpen)} />

      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header />

        <div className="bg-[#00a651] px-4 py-2 flex items-center justify-between text-white text-[12px] font-medium shrink-0">
          <div className="flex items-center gap-2">
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>
            <span>Trang chủ &gt; Chăm sóc khách hàng &gt; Quản lý đơn hàng</span>
          </div>
          <div className="flex items-center gap-4">
            <span>{currentTime}</span>
            <div className="flex items-center gap-1">
              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
              <span>Thứ tư - 04/02/2026</span>
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-3 space-y-3 scrollbar-thin">
          <FilterPanel 
            filters={filters} 
            onFilterChange={handleFilterChange} 
            onSearch={applyFilters}
          />

          <OrderTable 
            orders={filteredOrders} 
            onVerifyClick={(order) => setSelectedOrder(order)} 
          />
        </div>
      </main>

      {selectedOrder && (
        <VerifyModal 
          order={selectedOrder} 
          onClose={() => setSelectedOrder(null)}
          onConfirm={(status) => handleVerify(selectedOrder.id, status)}
        />
      )}
    </div>
  );
};

