                      <p className="text-sm font-medium">Không tìm thấy đơn cứu hộ nào khớp với bộ lọc.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showFilters && (
        <FilterPopup 
          initialFilters={supervisionFilters}
          onApply={setSupervisionFilters}
          onClose={() => setShowFilters(false)}
        />
      )}
    </div>
  );
};

