              )}
            </tbody>
          </table>
        </div>
      </div>

      {showFilters && (
        <FilterPopup 
          initialFilters={supervisionFilters}
          onApply={setSupervisionFilters}
          onClose={() => setShowFilters(false)}
        />
      )}
    </div>
  );
