  waitTo: string;
}

export interface FilterState {
  orderCode: string;
  phone: string;
  plate: string;
  service: string;
  partner: string;
  tollStation: string;
  orderStatus: string;
  requestStatus: string;
  supporter: string; // Changed from verificationStatus
