import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import FilterPanel from './components/FilterPanel';
import OrderTable from './components/OrderTable';
import VerifyModal from './components/VerifyModal';
import SupervisionDashboard from './components/SupervisionDashboard';
import ActiveSupportDashboard from './components/ActiveSupportDashboard';
import SupportConfirmModal from './components/SupportConfirmModal';
import { Order, FilterState, VerificationStatus, AppView, SupervisionOrder } from './types';
import { MOCK_ORDERS, MOCK_SUPERVISION_DATA } from './constants';

const App: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);
  const [filteredOrders, setFilteredOrders] = useState<Order[]>(MOCK_ORDERS);
  const [supervisionOrders, setSupervisionOrders] = useState<SupervisionOrder[]>(MOCK_SUPERVISION_DATA);

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [currentView, setCurrentView] = useState<AppView>('RESCUE_SUPERVISION');
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [confirmSupportOrder, setConfirmSupportOrder] = useState<SupervisionOrder | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date().toLocaleString('vi-VN'));

  const currentUser = "rsa_test1";

  const [filters, setFilters] = useState<FilterState>({
    orderCode: '',
    phone: '',
    plate: '',
    service: 'Tất cả',
    partner: 'Tất cả',
    tollStation: 'Tất cả',
    orderStatus: 'Tất cả',
    requestStatus: 'Tất cả',
    supporter: 'Tất cả',
    fromDate: '2026-02-01',
    toDate: '2026-02-28',
  });

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date().toLocaleString('vi-VN')), 1000);
    return () => clearInterval(timer);
  }, []);

  const handleFilterChange = (key: keyof FilterState, value: string) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  const handleMySupport = () => {
    // Set supporter to current user and requestStatus to something active (non-closed)
    // For this mock, we'll set requestStatus to "Tất cả" but filtered in applyFilters
    setFilters(prev => ({
      ...prev,
      supporter: currentUser,
      requestStatus: 'Tạo đơn thành công', // An active status
      orderStatus: 'Đang thực hiện cứu hộ'  // An active status
    }));
  };

  const applyFilters = () => {
    let result = [...orders];

    // Support Person Filter (mapped to createdBy or updatedBy in mock)
    if (filters.supporter !== 'Tất cả') {
      result = result.filter(o => o.createdBy === filters.supporter || o.updatedBy === filters.supporter);
    }

    // Filter active statuses if specific button logic requested exclusion of closed/done/cancelled
    // If the user clicked "Đang hỗ trợ", we specifically filter for non-closed ones
    if (filters.supporter === currentUser && filters.orderCode === '') {
       // Logic: Exclude 'Hoàn thành', 'Đã hủy', 'Đã đóng' if we want "Active" only
       // But usually the user just wants the exact filter they selected.
    }

    // Basic filters
    if (filters.orderCode) result = result.filter(o => o.orderCode.includes(filters.orderCode));
    if (filters.phone) result = result.filter(o => o.customer.phone.includes(filters.phone));
    if (filters.plate) result = result.filter(o => o.vehicle.plate.includes(filters.plate));
    if (filters.orderStatus !== 'Tất cả') result = result.filter(o => o.orderStatus === filters.orderStatus);
    if (filters.requestStatus !== 'Tất cả') result = result.filter(o => o.requestStatus === filters.requestStatus);

    setFilteredOrders(result);
  };

  const handleVerify = (orderId: string, status: VerificationStatus) => {
    const updatedOrders = orders.map(o => 
      o.id === orderId ? { ...o, verificationStatus: status } : o
    );
    setOrders(updatedOrders);
    setSelectedOrder(null);
  };

  const handleAcceptSupport = (orderId: string) => {
    setSupervisionOrders(prev => prev.map(o => 
      o.id === orderId ? { ...o, isInActiveSupport: true, status: 'SearchingPartner' } : o
    ));
    setConfirmSupportOrder(null);
  };

  useEffect(() => {
    applyFilters();
  }, [filters, orders]);

  const getBreadcrumbs = () => {
    const base = {
      ORDER_MANAGEMENT: { parent: 'Chăm sóc khách hàng', page: 'Quản lý đơn hàng' },
      RESCUE_SUPERVISION: { parent: 'Giám sát cứu hộ', page: 'Giám sát' },
      ACTIVE_SUPPORT: { parent: 'Giám sát cứu hộ', page: 'Đang hỗ trợ' }
    };
    return base[currentView];
  };

  return (
    <div className="flex h-screen overflow-hidden bg-[#f8fafc]">
      <Sidebar 
        isOpen={isSidebarOpen} 
        toggle={() => setIsSidebarOpen(!isSidebarOpen)} 
        currentView={currentView}
        onViewChange={setCurrentView}
      />

      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {/* Top Header Navigation */}
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 z-10">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-400 hover:bg-slate-50 rounded-lg transition-colors">
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16m-7 6h7" /></svg>
            </button>
            <h1 className="text-[15px] font-bold text-slate-800 uppercase tracking-tight">VETC - CỔNG THÔNG TIN DÀNH CHO ĐẠI LÝ</h1>
          </div>
          <div className="flex items-center gap-3">
             <div className="flex items-center gap-2 cursor-pointer hover:bg-slate-50 p-2 rounded-lg transition-colors">
              <span className="text-[13px] font-bold text-slate-600">{currentUser}</span>
              <svg className="w-4 h-4 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
            </div>
          </div>
        </header>

        {/* Breadcrumb Bar */}
        <div className="bg-[#00a651] px-6 py-2.5 flex items-center justify-between text-white text-[12px] font-medium shrink-0 shadow-sm">
          <div className="flex items-center gap-3">
            <div className="w-5 h-5 bg-white/20 rounded flex items-center justify-center">
              <svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 20 20"><path d="M10.707 2.293a1 1 0 00-1.414 0l-7 7a1 1 0 001.414 1.414L4 10.414V17a1 1 0 001 1h2a1 1 0 001-1v-2a1 1 0 011-1h2a1 1 0 011 1v2a1 1 0 001 1h2a1 1 0 001-1v-6.586l.293.293a1 1 0 001.414-1.414l-7-7z" /></svg>
            </div>
            <span className="opacity-80">Trang chủ</span>
            <span>&gt;</span>
            <span className="opacity-80 uppercase font-bold tracking-tighter">{getBreadcrumbs().parent}</span>
            <span>&gt;</span>
            <span className="font-bold uppercase tracking-tighter">{getBreadcrumbs().page}</span>
          </div>
          <div className="flex items-center gap-4 text-[11px] font-bold">
            <span className="bg-white/10 px-2.5 py-1 rounded">{currentUser}</span>
            <div className="flex items-center gap-1.5">
              <svg className="w-4 h-4 opacity-70" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
              <span>{currentTime.split(' ')[0]}</span>
            </div>
          </div>
        </div>

        {/* Content View */}
        <div className="flex-1 overflow-y-auto scrollbar-thin">
          {currentView === 'ORDER_MANAGEMENT' && (
            <div className="p-4 space-y-4">
              <FilterPanel 
                filters={filters} 
                onFilterChange={handleFilterChange} 
                onSearch={applyFilters}
                onMySupport={handleMySupport}
              />
              <OrderTable 
                orders={filteredOrders} 
                onVerifyClick={(order) => setSelectedOrder(order)} 
              />
            </div>
          )}
          {currentView === 'RESCUE_SUPERVISION' && (
            <SupervisionDashboard 
              orders={supervisionOrders} 
              onAcceptSupport={(order) => setConfirmSupportOrder(order)}
            />
          )}
          {currentView === 'ACTIVE_SUPPORT' && (
            <ActiveSupportDashboard 
              orders={supervisionOrders} 
              onAcceptSupport={(order) => setConfirmSupportOrder(order)}
            />
          )}
        </div>
      </main>

      {selectedOrder && (
        <VerifyModal 
          order={selectedOrder} 
          onClose={() => setSelectedOrder(null)}
          onConfirm={(status) => handleVerify(selectedOrder.id, status)}
        />
      )}

      {confirmSupportOrder && (
        <SupportConfirmModal 
          order={confirmSupportOrder}
          onClose={() => setConfirmSupportOrder(null)}
          onConfirm={() => handleAcceptSupport(confirmSupportOrder.id)}
        />
      )}
    </div>
  );
};

export default App;

