import React, { useState, useRef, useEffect } from 'react';
import { FilterState } from '../types';

interface FilterPanelProps {
  filters: FilterState;
  onFilterChange: (key: keyof FilterState, value: any) => void;
  onSearch: () => void;
  onMySupport: () => void;
}

const FilterPanel: React.FC<FilterPanelProps> = ({ filters, onFilterChange, onSearch, onMySupport }) => {
  const [isStatusOpen, setIsStatusOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const statusOptions = [
    { value: 'Created', label: 'Mới tạo (Created)' },
    { value: 'Payment', label: 'Chờ thanh toán (Payment)' },
    { value: 'Confirm', label: 'Xác nhận (Confirm)' },
    { value: 'Quotation', label: 'Báo giá (Quotation)' },
    { value: 'Rescue', label: 'Đang cứu hộ (Rescue)' },
    { value: 'Done', label: 'Hoàn thành (Done)' },
    { value: 'Cancel', label: 'Đã hủy (Cancel)' },
  ];

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsStatusOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleStatus = (statusValue: string) => {
    let newStatuses = [...filters.orderStatus];
    if (statusValue === 'Tất cả') {
      newStatuses = ['Tất cả'];
    } else {
      // Remove 'Tất cả' if selecting a specific one
      newStatuses = newStatuses.filter(s => s !== 'Tất cả');
      if (newStatuses.includes(statusValue)) {
        newStatuses = newStatuses.filter(s => s !== statusValue);
        if (newStatuses.length === 0) newStatuses = ['Tất cả'];
      } else {
        newStatuses.push(statusValue);
      }
    }
    onFilterChange('orderStatus', newStatuses);
  };

  const getStatusLabel = () => {
    if (filters.orderStatus.includes('Tất cả')) return 'Tất cả';
    if (filters.orderStatus.length === 0) return 'Chọn trạng thái...';
    if (filters.orderStatus.length <= 2) {
      return statusOptions
        .filter(opt => filters.orderStatus.includes(opt.value))
        .map(opt => opt.label.split(' ')[0])
        .join(', ');
    }
    return `Đã chọn ${filters.orderStatus.length} trạng thái`;
  };

  const labelClass = "text-[12px] text-slate-700 w-[120px] shrink-0 font-medium";
  const inputClass = "w-full px-3 py-1.5 bg-white border border-slate-200 rounded text-[12px] focus:outline-none focus:border-emerald-500 transition-colors";
  const selectClass = "w-full px-3 py-1.5 bg-white border border-slate-200 rounded text-[12px] focus:outline-none focus:border-emerald-500 appearance-none bg-[url('data:image/svg+xml;charset=US-ASCII,%3Csvg%20width%3D%2220%22%20height%3D%2220%22%20viewBox%3D%220%200%2020%2020%22%20fill%3D%22none%22%20xmlns%3D%22http%3A//www.w3.org/2000/svg%22%3E%3Cpath%20d%3D%22M5%207.5L10%2012.5L15%207.5%22%20stroke%3D%22%2394a3b8%22%20stroke-width%3D%221.5%22%20stroke-linecap%3D%22round%22%20stroke-linejoin%3D%22round%22/%3E%3C/svg%3E')] bg-[length:16px_16px] bg-no-repeat bg-[right_8px_center] transition-colors cursor-pointer";

  return (
    <div className="bg-white border border-emerald-500 rounded overflow-hidden shadow-sm">
      <div className="bg-[#00a651] px-4 py-2 flex items-center gap-2">
        <svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
        </svg>
        <h2 className="text-white text-[13px] font-bold uppercase tracking-wider">TRA CỨU ĐƠN HÀNG</h2>
      </div>

      <div className="p-6 space-y-4">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-x-12 gap-y-4">
          <div className="flex items-center gap-2">
            <label className={labelClass}>Mã đơn hàng</label>
            <input 
              type="text" 
              className={inputClass} 
              value={filters.orderCode}
              onChange={(e) => onFilterChange('orderCode', e.target.value)}
              placeholder="Nhập mã đơn..."
