import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import FilterPanel from './components/FilterPanel';
import OrderTable from './components/OrderTable';
import VerifyModal from './components/VerifyModal';
import SupervisionDashboard from './components/SupervisionDashboard';
import ActiveSupportDashboard from './components/ActiveSupportDashboard';
import SupportConfirmModal from './components/SupportConfirmModal';
import { Order, FilterState, VerificationStatus, AppView, SupervisionOrder, UserRole } from './types';
import { MOCK_ORDERS, MOCK_SUPERVISION_DATA } from './constants';

const App: React.FC = () => {
  const currentUser = "rsa_test1";

  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);
  const [filteredOrders, setFilteredOrders] = useState<Order[]>(MOCK_ORDERS);
  const [supervisionOrders, setSupervisionOrders] = useState<SupervisionOrder[]>(MOCK_SUPERVISION_DATA);

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [currentView, setCurrentView] = useState<AppView>('ORDER_MANAGEMENT');
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [confirmSupportOrder, setConfirmSupportOrder] = useState<SupervisionOrder | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date().toLocaleString('vi-VN'));
  const [userRole, setUserRole] = useState<UserRole>('CSKH');

  const [filters, setFilters] = useState<FilterState>({
    orderCode: '',
    phone: '',
    plate: '',
    service: 'Tất cả',
    partner: 'Tất cả',
    tollStation: 'Tất cả',
    orderStatus: ['INITIAL'], 
    requestStatus: ['Tất cả'],
    supporter: currentUser,
    fromDate: '2026-02-01',
    toDate: '2026-02-28',
  });

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date().toLocaleString('vi-VN')), 1000);
    return () => clearInterval(timer);
  }, []);

  const handleRoleSwitch = (role: UserRole) => {
    setUserRole(role);
    if (role === 'CSKH') {
      setFilters(prev => ({
        ...prev,
        supporter: currentUser,
        orderStatus: ['INITIAL'],
        requestStatus: ['Tất cả']
      }));
    } else {
      setFilters(prev => ({
        ...prev,
        supporter: 'Tất cả',
        orderStatus: ['Tất cả'],
        requestStatus: ['Tất cả']
      }));
    }
  };

  const handleFilterChange = (key: keyof FilterState, value: any) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  const handleMySupport = () => {
    setFilters(prev => ({
      ...prev,
      supporter: currentUser,
      orderStatus: ['INITIAL'],
      requestStatus: ['Tất cả']
    }));
  };

  const applyFilters = () => {
    let result = [...orders];

    if (filters.supporter !== 'Tất cả') {
      result = result.filter(o => o.createdBy === filters.supporter || o.updatedBy === filters.supporter);
    }

    if (filters.orderCode) result = result.filter(o => o.orderCode.includes(filters.orderCode));
    if (filters.phone) result = result.filter(o => o.customer.phone.includes(filters.phone));
    if (filters.plate) result = result.filter(o => o.vehicle.plate.includes(filters.plate));

    if (!filters.orderStatus.includes('Tất cả') && filters.orderStatus.length > 0) {
      result = result.filter(o => filters.orderStatus.includes(o.orderStatus));
    }

    if (!filters.requestStatus.includes('Tất cả') && filters.requestStatus.length > 0) {
      result = result.filter(o => filters.requestStatus.includes(o.requestStatus));
    }

    setFilteredOrders(result);
  };

  const handleVerify = (orderId: string, status: VerificationStatus) => {
    const updatedOrders = orders.map(o => 
      o.id === orderId ? { ...o, verificationStatus: status } : o
    );
    setOrders(updatedOrders);
    setSelectedOrder(null);
  };

  const handleAcceptSupport = (orderId: string) => {
    setSupervisionOrders(prev => prev.map(o => 
      o.id === orderId ? { ...o, isInActiveSupport: true, status: 'SearchingPartner' } : o
    ));
    setConfirmSupportOrder(null);
  };

  useEffect(() => {
    applyFilters();
  }, [filters, orders]);

  const getBreadcrumbs = () => {
    const base = {
      ORDER_MANAGEMENT: { parent: 'Chăm sóc khách hàng', page: 'Quản lý đơn hàng' },
      RESCUE_SUPERVISION: { parent: 'Giám sát cứu hộ', page: 'Giám sát' },
      ACTIVE_SUPPORT: { parent: 'Giám sát cứu hộ', page: 'Đang hỗ trợ' }
    };
    return base[currentView];
  };

  return (
    <div className="flex h-screen overflow-hidden bg-[#f8fafc]">
      <Sidebar isOpen={isSidebarOpen} toggle={() => setIsSidebarOpen(!isSidebarOpen)} currentView={currentView} onViewChange={setCurrentView} userRole={userRole} currentUser={currentUser} />
      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 z-10">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-400 hover:bg-slate-50 rounded-lg"><svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16m-7 6h7" /></svg></button>
            <h1 className="text-[15px] font-bold text-slate-800 uppercase tracking-tight">VETC - CỔNG THÔNG TIN DÀNH CHO ĐẠI LÝ</h1>
          </div>
          <div className="flex items-center gap-6">
            <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200 shadow-inner">
              <button onClick={() => handleRoleSwitch('CSKH')} className={`px-4 py-1.5 rounded-lg text-[11px] font-black transition-all uppercase tracking-wider ${userRole === 'CSKH' ? 'bg-[#00a651] text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>CSKH</button>
              <button onClick={() => handleRoleSwitch('OSA')} className={`px-4 py-1.5 rounded-lg text-[11px] font-black transition-all uppercase tracking-wider ${userRole === 'OSA' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>OSA</button>
            </div>
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2 cursor-pointer hover:bg-slate-50 p-2 rounded-lg">
                <div className={`px-2 py-0.5 rounded text-[10px] font-black text-white ${userRole === 'CSKH' ? 'bg-emerald-600' : 'bg-indigo-600'}`}>{userRole}</div>
                <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center border-2 border-white shadow-sm overflow-hidden"><svg className="w-5 h-5 text-slate-400" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" /></svg></div>
                <div className="flex flex-col"><span className="text-[13px] font-bold text-slate-700 leading-none">{currentUser}</span></div>
              </div>
            </div>
          </div>
        </header>
        <div className="bg-[#00a651] px-6 py-2.5 flex items-center justify-between text-white text-[12px] font-medium shrink-0 shadow-sm">
          <div className="flex items-center gap-3">
            <div className="w-5 h-5 bg-white/20 rounded flex items-center justify-center"><svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 20 20"><path d="M10.707 2.293a1 1 0 00-1.414 0l-7 7a1 1 0 001.414 1.414L4 10.414V17a1 1 0 001 1h2a1 1 0 001-1v-2a1 1 0 011-1h2a1 1 0 011 1v2a1 1 0 001 1h2a1 1 0 001-1v-6.586l.293.293a1 1 0 001.414-1.414l-7-7z" /></svg></div>
            <span className="opacity-80">Trang chủ</span><span>&gt;</span><span className="opacity-80 uppercase font-bold">{getBreadcrumbs().parent}</span><span>&gt;</span><span className="font-bold uppercase">{getBreadcrumbs().page}</span>
          </div>
          <div className="flex items-center gap-4 text-[11px] font-bold">
            <div className="flex items-center gap-2"><span className={`px-2 py-0.5 rounded text-[9px] text-white ${userRole === 'CSKH' ? 'bg-emerald-700' : 'bg-indigo-700'}`}>{userRole}</span><span className="bg-white/10 px-2.5 py-1 rounded">{currentUser}</span></div>
            <span>{currentTime.split(' ')[0]}</span>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto scrollbar-thin">
          {currentView === 'ORDER_MANAGEMENT' && (
            <div className="p-4 space-y-4">
              <FilterPanel filters={filters} onFilterChange={handleFilterChange} onSearch={applyFilters} onMySupport={handleMySupport} />
              <OrderTable orders={filteredOrders} onVerifyClick={(order) => setSelectedOrder(order)} />
            </div>
          )}
          {currentView === 'RESCUE_SUPERVISION' && <SupervisionDashboard orders={supervisionOrders} onAcceptSupport={(order) => setConfirmSupportOrder(order)} />}
          {currentView === 'ACTIVE_SUPPORT' && <ActiveSupportDashboard orders={supervisionOrders} onAcceptSupport={(order) => setConfirmSupportOrder(order)} />}
        </div>
      </main>
      {selectedOrder && <VerifyModal order={selectedOrder} onClose={() => setSelectedOrder(null)} onConfirm={(status) => handleVerify(selectedOrder.id, status)} />}
      {confirmSupportOrder && <SupportConfirmModal order={confirmSupportOrder} onClose={() => setConfirmSupportOrder(null)} onConfirm={() => handleAcceptSupport(confirmSupportOrder.id)} />}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { FilterState } from '../types';
import { STATUS_MAPPING } from '../constants';

interface FilterPanelProps {
  filters: FilterState;
  onFilterChange: (key: keyof FilterState, value: any) => void;
  onSearch: () => void;
  onMySupport: () => void;
}

const FilterPanel: React.FC<FilterPanelProps> = ({ filters, onFilterChange, onSearch, onMySupport }) => {
  const [isStatusOpen, setIsStatusOpen] = useState(false);
  const [isRequestOpen, setIsRequestOpen] = useState(false);
  const statusRef = useRef<HTMLDivElement>(null);
  const requestRef = useRef<HTMLDivElement>(null);

  const orderStatusOptions = [
    { value: 'INITIAL', label: 'Khởi tạo (INITIAL)' },
    { value: 'CONFIRMED', label: 'Xác nhận (CONFIRMED)' },
    { value: 'ASSIGNING', label: 'Điều phối (ASSIGNING)' },
    { value: 'IN_PROGRESS', label: 'Đang thực hiện (IN_PROGRESS)' },
    { value: 'COMPLETED', label: 'Hoàn thành (COMPLETED)' },
    { value: 'FAILED', label: 'Thất bại (FAILED)' },
  ];

  const availableRequestStatuses = React.useMemo(() => {
    if (filters.orderStatus.includes('Tất cả')) {
      return Array.from(new Set(Object.values(STATUS_MAPPING).flat())).sort();
    }
    return Array.from(new Set(filters.orderStatus.flatMap(status => STATUS_MAPPING[status] || []))).sort();
  }, [filters.orderStatus]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (statusRef.current && !statusRef.current.contains(event.target as Node)) setIsStatusOpen(false);
      if (requestRef.current && !requestRef.current.contains(event.target as Node)) setIsRequestOpen(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleOrderStatus = (val: string) => {
    let next = [...filters.orderStatus];
    if (val === 'Tất cả') {
      next = ['Tất cả'];
    } else {
      next = next.filter(s => s !== 'Tất cả');
      if (next.includes(val)) {
        next = next.filter(s => s !== val);
        if (next.length === 0) next = ['Tất cả'];
      } else {
        next.push(val);
      }
    }
    onFilterChange('orderStatus', next);
    onFilterChange('requestStatus', ['Tất cả']);
  };

  const toggleRequestStatus = (val: string) => {
    let next = [...filters.requestStatus];
    if (val === 'Tất cả') {
      next = ['Tất cả'];
    } else {
      next = next.filter(s => s !== 'Tất cả');
      if (next.includes(val)) {
        next = next.filter(s => s !== val);
        if (next.length === 0) next = ['Tất cả'];
      } else {
        next.push(val);
      }
    }
    onFilterChange('requestStatus', next);
  };

  const labelClass = "text-[12px] text-slate-700 w-[120px] shrink-0 font-medium";
  const inputClass = "w-full px-3 py-1.5 bg-white border border-slate-200 rounded text-[12px] focus:outline-none focus:border-emerald-500 transition-colors";
