  id: string;
  orderCode: string;
  service: string[];
  quantity: number;
  providerFee: number;
  requestStatus: string;
  orderStatus: string;
  verificationStatus: VerificationStatus;
  customer: {
    name: string;
    phone: string;
  };
  vehicle: {
    plate: string;
    brand: string;
    model: string;
  };
  address: string;
  createdAt: string;
