import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import FilterPanel from './components/FilterPanel';
import OrderTable from './components/OrderTable';
import VerifyModal from './components/VerifyModal';
import SupervisionDashboard from './components/SupervisionDashboard';
import ActiveSupportDashboard from './components/ActiveSupportDashboard';
import SupportConfirmModal from './components/SupportConfirmModal';
import AssignModal from './components/AssignModal';
import { Order, FilterState, VerificationStatus, AppView, SupervisionOrder, UserRole } from './types';
import { MOCK_ORDERS, MOCK_SUPERVISION_DATA, STATUS_MAPPING } from './constants';

const App: React.FC = () => {
  const currentUser = "rsa_test1";

  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);
  const [filteredOrders, setFilteredOrders] = useState<Order[]>(MOCK_ORDERS);
  const [supervisionOrders, setSupervisionOrders] = useState<SupervisionOrder[]>(MOCK_SUPERVISION_DATA);

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [currentView, setCurrentView] = useState<AppView>('ORDER_MANAGEMENT');
  const [selectedOrderForVerify, setSelectedOrderForVerify] = useState<Order | null>(null);
  const [selectedOrderForSupport, setSelectedOrderForSupport] = useState<Order | null>(null);
  const [selectedOrderForAssign, setSelectedOrderForAssign] = useState<Order | null>(null);
  const [confirmSupportOrder, setConfirmSupportOrder] = useState<SupervisionOrder | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date().toLocaleString('vi-VN'));
  const [userRole, setUserRole] = useState<UserRole>('CSKH');

  const [filters, setFilters] = useState<FilterState>({
    orderCode: '',
    phone: '',
    plate: '',
    service: 'Tất cả',
    partner: 'Tất cả',
    tollStation: 'Tất cả',
    orderStatus: ['INITIAL'], 
    requestStatus: ['Tất cả'],
    verificationStatus: 'Tất cả',
    supporter: 'NONE', 
    fromDate: '2026-02-01',
    toDate: '2026-02-28',
  });

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date().toLocaleString('vi-VN')), 1000);
    return () => clearInterval(timer);
  }, []);

  const handleRoleSwitch = (role: UserRole) => {
    setUserRole(role);
    if (role === 'CSKH') {
      setFilters(prev => ({
        ...prev,
        supporter: 'NONE',
        orderStatus: ['INITIAL'],
        requestStatus: ['Tất cả'],
        verificationStatus: 'Tất cả'
      }));
    } else {
      setFilters(prev => ({
        ...prev,
        supporter: 'NONE',
        orderStatus: ['INITIAL', 'CONFIRMED', 'ASSIGNING', 'IN_PROGRESS'],
        requestStatus: ['Tất cả'],
        verificationStatus: 'Tất cả'
      }));
    }
  };

  const handleFilterChange = (key: keyof FilterState, value: any) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  const handleMySupport = () => {
    if (userRole === 'OSA') {
      setFilters(prev => ({
        ...prev,
        supporter: currentUser,
        orderStatus: ['INITIAL', 'CONFIRMED', 'ASSIGNING', 'IN_PROGRESS'],
        requestStatus: ['Tất cả']
      }));
    } else {
      setFilters(prev => ({
        ...prev,
        supporter: currentUser,
        orderStatus: ['INITIAL'],
        requestStatus: ['Tất cả']
      }));
    }
  };

  const handleNotSupported = () => {
    if (userRole === 'OSA') {
      setFilters(prev => ({
        ...prev,
        supporter: 'NONE',
        orderStatus: ['INITIAL', 'CONFIRMED', 'ASSIGNING', 'IN_PROGRESS'],
        requestStatus: ['Tất cả']
      }));
    } else {
      setFilters(prev => ({
        ...prev,
        supporter: 'NONE',
        orderStatus: ['INITIAL'],
        requestStatus: ['Tất cả']
      }));
    }
  };

  const applyFilters = () => {
    let result = [...orders];
    if (filters.supporter === 'NONE') {
      result = result.filter(o => !o.updatedBy || o.updatedBy === '---' || o.updatedBy === '');
    } else if (filters.supporter !== 'Tất cả') {
      result = result.filter(o => o.createdBy === filters.supporter || o.updatedBy === filters.supporter);
    }
    if (filters.orderCode) result = result.filter(o => o.orderCode.toLowerCase().includes(filters.orderCode.toLowerCase()));
    if (filters.phone) result = result.filter(o => o.customer.phone.includes(filters.phone));
    if (filters.plate) result = result.filter(o => o.vehicle.plate.toLowerCase().includes(filters.plate.toLowerCase()));
    if (!filters.orderStatus.includes('Tất cả') && filters.orderStatus.length > 0) {
      result = result.filter(o => filters.orderStatus.includes(o.orderStatus));
    }
    if (!filters.requestStatus.includes('Tất cả') && filters.requestStatus.length > 0) {
      result = result.filter(o => filters.requestStatus.includes(o.requestStatus));
    }
    if (filters.verificationStatus !== 'Tất cả') {
      result = result.filter(o => o.verificationStatus === filters.verificationStatus);
    }
    if (filters.service !== 'Tất cả') {
      result = result.filter(o => o.service.some(s => s.includes(filters.service)));
    }
    setFilteredOrders(result);
  };

  const handleOrderAction = (order: Order) => {
    const currentSupporter = order.updatedBy || '---';

    // Logic 1: If assigned to current user, go to detail
    if (currentSupporter === currentUser) {
      alert(`Chuyển đến màn hình chi tiết đơn hàng: ${order.orderCode}`);
      return;
    }

    // Logic 2: If unassigned
    if (currentSupporter === '---' || currentSupporter === '') {
      if (userRole === 'CSKH') {
        setSelectedOrderForSupport(order);
      } else {
        setSelectedOrderForAssign(order);
      }
      return;
    }

    // Logic 3: Assigned to others (should be disabled in UI, but handled for safety)
    console.warn("Order is handled by someone else.");
  };

  const handleAssignConfirm = (orderId: string, assignedTo: string) => {
    const updatedOrders = orders.map(o => 
      o.id === orderId ? { ...o, updatedBy: assignedTo } : o
    );
    setOrders(updatedOrders);
    setSelectedOrderForAssign(null);
    setSelectedOrderForSupport(null);
  };

  const handleVerifyResult = (orderId: string, status: VerificationStatus) => {
    const updatedOrders = orders.map(o => 
      o.id === orderId ? { ...o, verificationStatus: status, updatedBy: currentUser } : o
    );
    setOrders(updatedOrders);
    setSelectedOrderForVerify(null);
  };

  const handleAcceptSupportFromSupervision = (orderId: string) => {
    setSupervisionOrders(prev => prev.map(o => 
      o.id === orderId ? { ...o, isInActiveSupport: true, status: 'SearchingPartner' } : o
    ));
    setConfirmSupportOrder(null);
  };

  useEffect(() => {
    applyFilters();
  }, [filters, orders]);

  const getBreadcrumbs = () => {
    const base = {
