import React, { useState, useEffect } from 'react';
import { Order, UserRole } from '../types';

interface OrderTableProps {
  orders: Order[];
  onVerifyClick: (order: Order) => void;
  currentUser: string;
  userRole: UserRole;
}

const OrderTable: React.FC<OrderTableProps> = ({ orders, onVerifyClick, currentUser, userRole }) => {
  const [now, setNow] = useState(new Date());

  // Update the "now" reference every second to refresh wait times
  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const calculateWaitTime = (createdAtStr: string) => {
    try {
      // Parse '01/02/2026 - 08:00:00'
      const [datePart, timePart] = createdAtStr.split(' - ');
      const [day, month, year] = datePart.split('/').map(Number);
      const [hour, min, sec] = timePart.split(':').map(Number);
      const createdDate = new Date(year, month - 1, day, hour, min, sec);

      const diffMs = now.getTime() - createdDate.getTime();
      if (diffMs < 0) return '0p';

      const totalSeconds = Math.floor(diffMs / 1000);
      const minutes = Math.floor(totalSeconds / 60);
      const seconds = totalSeconds % 60;

      if (minutes >= 60) {
        const hours = Math.floor(minutes / 60);
        return `${hours}h ${minutes % 60}p`;
      }
      return `${minutes}p ${seconds}s`;
    } catch (e) {
      return '---';
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'INITIAL':
        return <span className="px-2 py-0.5 bg-blue-50 text-blue-600 rounded-full font-bold border border-blue-100 uppercase text-[9px]">Khởi tạo</span>;
      case 'CONFIRMED':
        return <span className="px-2 py-0.5 bg-emerald-50 text-emerald-600 rounded-full font-bold border border-emerald-100 uppercase text-[9px]">Xác nhận</span>;
      case 'ASSIGNING':
        return <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 rounded-full font-bold border border-indigo-100 uppercase text-[9px]">Điều phối</span>;
      case 'IN_PROGRESS':
        return <span className="px-2 py-0.5 bg-amber-50 text-amber-600 rounded-full font-bold border border-amber-100 uppercase text-[9px]">Đang xử lý</span>;
      case 'COMPLETED':
        return <span className="px-2 py-0.5 bg-slate-50 text-slate-500 rounded-full font-bold border border-slate-200 uppercase text-[9px]">Hoàn thành</span>;
      case 'FAILED':
        return <span className="px-2 py-0.5 bg-red-50 text-red-600 rounded-full font-bold border border-red-100 uppercase text-[9px]">Thất bại</span>;
      default:
        return <span className="text-slate-400 italic text-[10px]">{status}</span>;
    }
  };

  const isAssignedToOthers = (order: Order) => {
    const supporter = order.updatedBy || '---';
    return supporter !== '---' && supporter !== '' && supporter !== currentUser;
  };

  const getActionTitle = (order: Order) => {
    if (isAssignedToOthers(order)) return `Đang được hỗ trợ bởi ${order.updatedBy}`;
    const supporter = order.updatedBy || '---';
    if (supporter === '---' || supporter === '') {
      return userRole === 'CSKH' ? "Nhận hỗ trợ đơn này" : "Phân công hỗ trợ đơn này";
    }
    return "Xem chi tiết đơn hàng";
  };

  return (
    <div className="bg-white border border-emerald-500 rounded overflow-hidden flex flex-col mb-4 shadow-sm">
      <div className="bg-[#00a651] px-4 py-2 flex items-center justify-between">
        <h3 className="text-white font-bold text-sm uppercase tracking-wider">Danh sách đơn cứu hộ</h3>
        <span className="text-white/70 text-[10px] font-medium">{orders.length} kết quả</span>
      </div>

      <div className="overflow-x-auto scrollbar-thin">
        <table className="w-full text-left border-collapse min-w-[2150px]">
          <thead>
            <tr className="bg-slate-50 text-slate-500 text-[10px] font-bold uppercase tracking-wider">
              <th rowSpan={2} className="border p-3 w-12 text-center sticky left-0 bg-slate-50 z-20">STT</th>
              <th rowSpan={2} className="border p-3 w-32 text-center sticky left-12 bg-slate-50 z-20">Thao tác</th>
              <th colSpan={5} className="border p-3 w-40 text-center">Thông tin đơn hàng</th>
              <th colSpan={3} className="border p-3 w-48 text-center">Thông tin khách hàng</th>
              <th colSpan={3} className="border p-3 w-36 text-center">Thông tin đối tác hỗ trợ</th>
              <th colSpan={2} className="border p-3 w-32 text-center">Thông tin hệ thống</th>
            </tr>
            <tr className="bg-slate-50 text-slate-500 text-[10px] font-bold uppercase tracking-wider">
              <th className="border p-3 w-40 text-center">Mã đơn hàng</th>
              <th className="border p-3 w-48 text-center">Dịch vụ</th>
              <th className="border p-3 w-32 text-center">Thời gian chờ</th>
              <th className="border p-3 w-36 text-center">Trạng thái</th>
              <th className="border p-3 w-32 text-center">Người hỗ trợ</th>
              <th className="border p-3 w-48 text-center">Khách hàng</th>
              <th className="border p-3 w-40 text-center">Xe</th>
              <th className="border p-3 w-64 text-center">Địa chỉ cứu hộ</th>
              <th className="border p-3 w-40 text-center">Đối tác</th>
              <th className="border p-3 w-40 text-center">Tài xế</th>
              <th className="border p-3 w-48 text-center">Điểm xử lý</th>
              <th className="border p-3 w-44 text-center">Ngày tạo</th>
              <th className="border p-3 w-32 text-center">Người tạo</th>
            </tr>
          </thead>
          <tbody className="text-[11px] text-slate-700 bg-white">
            {orders.length > 0 ? orders.map((order, idx) => {
              const disabled = isAssignedToOthers(order);
              const waitTime = calculateWaitTime(order.createdAt);
              return (
                <tr key={order.id} className="hover:bg-slate-50 border-b last:border-b-0 group">
                  <td className="border-r p-3 text-center font-medium text-slate-400 sticky left-0 bg-white group-hover:bg-slate-50 z-10">
                    {idx + 1}
                  </td>
                  <td className="border-r p-3 sticky left-12 bg-white group-hover:bg-slate-50 z-10">
                    <div className="flex items-center justify-center gap-3">
                      <button className="p-1.5 text-slate-400 hover:text-blue-500 hover:bg-blue-50 rounded transition-colors" title="Xem nhanh">
                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                        </svg>
                      </button>

                      <button 
                        disabled={disabled}
                        onClick={() => onVerifyClick(order)}
                        title={getActionTitle(order)}
                        className={`p-1.5 rounded transition-all ${disabled ? 'text-slate-200 cursor-not-allowed opacity-30' : 'text-emerald-600 hover:bg-emerald-50 hover:scale-110 active:scale-95'}`}
                      >
                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                        </svg>
                      </button>
                    </div>
                  </td>
                  <td className="border-r p-3">
                    <div className="flex flex-col gap-1">
                      <span className="font-bold text-slate-900">{order.orderCode}</span>
                      <div className="flex gap-1">
                        <span className="px-1 py-0.5 rounded-[2px] bg-blue-50 text-blue-500 text-[8px] font-black uppercase border border-blue-100">{order.typeBadge}</span>
                        <span className="px-1 py-0.5 rounded-[2px] bg-emerald-50 text-emerald-500 text-[8px] font-black uppercase border border-emerald-100">{order.sourceBadge}</span>
                      </div>
                    </div>
                  </td>
                  <td className="border-r p-3">
                    <div className="flex flex-wrap gap-1">
                      {order.service.map((s, i) => (
                        <span key={i} className="px-1.5 py-0.5 bg-slate-50 text-slate-600 rounded border border-slate-100 font-medium whitespace-nowrap">
                          {s}
                        </span>
                      ))}
                    </div>
                  </td>
                  <td className="border-r p-3 text-center">
                    <span className={`font-black text-[12px] tracking-tight ${waitTime.includes('h') ? 'text-red-500' : 'text-slate-700'}`}>
                      {waitTime}
                    </span>
                  </td>
                  <td className="border-r p-3">
                    <div className="flex flex-col gap-1.5">
                      {getStatusBadge(order.orderStatus)}
                      <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded w-fit ${order.verificationStatus === 'Đã xác minh' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-500'}`}>
                        {order.verificationStatus}
                      </span>
                    </div>
                  </td>
                  <td className="border-r p-3">
                    <span className={`text-[10px] font-black uppercase tracking-tighter ${order.updatedBy === currentUser ? 'text-blue-600' : 'text-slate-600'}`}>
                      {order.updatedBy || '---'}
                    </span>
                  </td>
                  <td className="border-r p-3">
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-800 uppercase tracking-tighter text-[11px] leading-tight">{order.customer.name}</span>
                      <span className="text-slate-500 font-medium">{order.customer.phone}</span>
                    </div>
                  </td>
                  <td className="border-r p-3">
                    <div className="flex flex-col">
                      <span className="font-black text-slate-900 leading-none bg-slate-50 border border-slate-200 px-1.5 py-1 rounded w-fit text-[11px] mb-1">{order.vehicle.plate}</span>
                      <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">{order.vehicle.brand} {order.vehicle.model}</span>
                    </div>
                  </td>
                  <td className="border-r p-3">
                    <span className="text-slate-500 italic leading-tight text-[10px] line-clamp-2">{order.address}</span>
                  </td>
                  <td className="border-r p-3">
                    <span className="font-bold text-blue-600 uppercase tracking-tighter text-[11px]">{order.supportPartner || '---'}</span>
                  </td>
                  <td className="border-r p-3">
                    {order.driver ? (
                      <div className="flex flex-col">
                        <span className="font-bold text-slate-700 text-[11px]">{order.driver.name}</span>
                        <span className="text-slate-400 text-[10px] font-medium">{order.driver.phone}</span>
                      </div>
                    ) : '---'}
                  </td>
                  <td className="border-r p-3">
                    <div className="flex flex-col gap-1">
                      <span className="font-bold text-slate-600 text-[10px] uppercase leading-tight">
                        {order.rescueStation || 'Chưa xác định'}
                      </span>
                      {order.towToLocation && (
                        <span className="text-[9px] text-slate-400 italic">Kéo về: {order.towToLocation}</span>
                      )}
                    </div>
                  </td>
                  <td className="border-r p-3 whitespace-nowrap text-slate-500 font-medium text-center">{order.createdAt}</td>
                  <td className="p-3">
                    <div className="flex items-center gap-1.5 justify-center">
                      <div className="w-4 h-4 rounded-full bg-slate-100 flex items-center justify-center border border-slate-200">
                        <svg className="w-2.5 h-2.5 text-slate-400" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" /></svg>
                      </div>
                      <span className="text-slate-800 font-black uppercase text-[10px] tracking-tighter">{order.createdBy}</span>
                    </div>
                  </td>
                </tr>
              );
            }) : (
              <tr><td colSpan={15} className="p-16 text-center text-slate-400 font-bold uppercase tracking-widest bg-slate-50/20">KHÔNG TÌM THẤY DỮ LIỆU PHÙ HỢP</td></tr>
            )}
          </tbody>
        </table>
      </div>

      <div className="px-4 py-3 border-t flex items-center justify-end gap-4 bg-white text-[11px] text-slate-500 shrink-0">
        <span className="font-medium">
          {orders.length > 0 ? `Hiển thị 1-${orders.length} trên tổng số ${orders.length}` : '0 kết quả'}
        </span>
        <div className="flex items-center gap-1">
          <button className="p-1.5 hover:bg-slate-100 rounded text-slate-300 disabled:opacity-30" disabled>&lt;</button>
          <button className="w-6 h-6 flex items-center justify-center bg-emerald-50 border border-emerald-500 text-emerald-600 rounded font-bold">1</button>
          <button className="p-1.5 hover:bg-slate-100 rounded text-slate-300 disabled:opacity-30" disabled>&gt;</button>
        </div>
      </div>
    </div>
  );
};

export default OrderTable;

import React, { useState, useRef, useEffect } from 'react';
import { FilterState, UserRole } from '../types';
import { STATUS_MAPPING, REQUEST_STATUS_LABELS } from '../constants';

interface FilterPanelProps {
  filters: FilterState;
  onFilterChange: (key: keyof FilterState, value: any) => void;
  onSearch: () => void;
  onMySupport: () => void;
  onNotSupported: () => void;
  userRole: UserRole;
}

const FilterPanel: React.FC<FilterPanelProps> = ({ filters, onFilterChange, onSearch, onMySupport, onNotSupported, userRole }) => {
  const [isStatusOpen, setIsStatusOpen] = useState(false);
  const [isRequestOpen, setIsRequestOpen] = useState(false);
  const statusRef = useRef<HTMLDivElement>(null);
  const requestRef = useRef<HTMLDivElement>(null);

  const orderStatusOptions = [
    { value: 'INITIAL', label: 'Khởi tạo (INITIAL)' },
    { value: 'CONFIRMED', label: 'Xác nhận (CONFIRMED)' },
    { value: 'ASSIGNING', label: 'Điều phối (ASSIGNING)' },
    { value: 'IN_PROGRESS', label: 'Đang thực hiện (IN_PROGRESS)' },
    { value: 'COMPLETED', label: 'Hoàn thành (COMPLETED)' },
    { value: 'FAILED', label: 'Thất bại (FAILED)' },
  ];

  const availableRequestStatuses = React.useMemo(() => {
    if (filters.orderStatus.includes('Tất cả')) {
      return Array.from(new Set(Object.values(STATUS_MAPPING).flat())).sort();
    }
    return Array.from(new Set(filters.orderStatus.flatMap(status => STATUS_MAPPING[status] || []))).sort();
  }, [filters.orderStatus]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (statusRef.current && !statusRef.current.contains(event.target as Node)) setIsStatusOpen(false);
      if (requestRef.current && !requestRef.current.contains(event.target as Node)) setIsRequestOpen(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleOrderStatus = (val: string) => {
    let next = [...filters.orderStatus];
    if (val === 'Tất cả') {
      next = ['Tất cả'];
    } else {
      next = next.filter(s => s !== 'Tất cả');
      if (next.includes(val)) {
        next = next.filter(s => s !== val);
        if (next.length === 0) next = ['Tất cả'];
      } else {
        next.push(val);
      }
    }
    onFilterChange('orderStatus', next);
    onFilterChange('requestStatus', ['Tất cả']);
  };

  const toggleRequestStatus = (val: string) => {
    let next = [...filters.requestStatus];
    if (val === 'Tất cả') {
      next = ['Tất cả'];
    } else {
      next = next.filter(s => s !== 'Tất cả');
      if (next.includes(val)) {
        next = next.filter(s => s !== val);
        if (next.length === 0) next = ['Tất cả'];
      } else {
        next.push(val);
      }
    }
    onFilterChange('requestStatus', next);
  };

  const labelClass = "text-[12px] text-slate-700 w-[120px] shrink-0 font-medium";
  const inputClass = "w-full px-3 py-1.5 bg-white border border-slate-200 rounded text-[12px] focus:outline-none focus:border-emerald-500 transition-colors";
  const selectClass = "w-full px-3 py-1.5 bg-white border border-slate-200 rounded text-[12px] focus:outline-none focus:border-emerald-500 appearance-none bg-[url('data:image/svg+xml;charset=US-ASCII,%3Csvg%20width%3D%2220%22%20height%3D%2220%22%20viewBox%3D%220%200%2020%2020%22%20fill%3D%22none%22%20xmlns%3D%22http%3A//www.w3.org/2000/svg%22%3E%3Cpath%20d%3D%22M5%207.5L10%2012.5L15%207.5%22%20stroke%3D%22%2394a3b8%22%20stroke-width%3D%221.5%22%20stroke-linecap%3D%22round%22%20stroke-linejoin%3D%22round%22/%3E%3C/svg%3E')] bg-[length:16px_16px] bg-no-repeat bg-[right_8px_center] transition-colors cursor-pointer";

  const getMultiLabel = (vals: string[], type: 'ORDER' | 'REQUEST' = 'ORDER') => {
    if (vals.includes('Tất cả')) return 'Tất cả';
    if (vals.length === 0) return 'Chọn...';
    if (vals.length === 1) {
      if (type === 'REQUEST') {
        const v = vals[0];
        return REQUEST_STATUS_LABELS[v] ? `${REQUEST_STATUS_LABELS[v]} (${v})` : v;
      }
      return vals[0];
    }
    return `Đã chọn ${vals.length}`;
  };

  return (
    <div className="bg-white border border-emerald-500 rounded shadow-sm relative z-30">
      <div className="bg-[#00a651] px-4 py-2 flex items-center gap-2 rounded-t-[3px]">
        <svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
        <h2 className="text-white text-[13px] font-bold uppercase tracking-wider">TRA CỨU ĐƠN HÀNG</h2>
      </div>

      <div className="p-6 space-y-4">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-x-12 gap-y-4">
          <div className="flex items-center gap-2">
            <label className={labelClass}>Mã đơn hàng</label>
            <input type="text" className={inputClass} value={filters.orderCode} onChange={(e) => onFilterChange('orderCode', e.target.value)} placeholder="Nhập mã đơn..." />
          </div>
          <div className="flex items-center gap-2">
            <label className={labelClass}>Số điện thoại</label>
            <input type="text" className={inputClass} value={filters.phone} onChange={(e) => onFilterChange('phone', e.target.value)} placeholder="09xx..." />
          </div>
          <div className="flex items-center gap-2">
            <label className={labelClass}>Biển số xe</label>
            <input type="text" className={inputClass} value={filters.plate} onChange={(e) => onFilterChange('plate', e.target.value)} placeholder="29A-xxxx..." />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-x-12 gap-y-4">
          <div className="flex items-center gap-2">
            <label className={labelClass}>Dịch vụ</label>
            <select className={selectClass} value={filters.service} onChange={(e) => onFilterChange('service', e.target.value)}>
              <option value="Tất cả">Tất cả</option>
              <option value="Kích bình ắc quy">Kích bình ắc quy</option>
              <option value="Thay lốp dự phòng">Thay lốp dự phòng</option>
              <option value="Cứu hộ kéo xe">Cứu hộ kéo xe</option>
            </select>
          </div>
          <div className="flex items-center gap-2">
            <label className={labelClass}>Đối tác</label>
            <select className={selectClass} value={filters.partner} onChange={(e) => onFilterChange('partner', e.target.value)}>
              <option value="Tất cả">Tất cả</option>
              <option value="CARPLA SERVICE">CARPLA SERVICE</option>
              <option value="RSA PARTNER">RSA PARTNER</option>
            </select>
          </div>
          <div className="flex items-center gap-2">
            <label className={labelClass}>Trạm cứu hộ</label>
            <select className={selectClass} value={filters.tollStation} onChange={(e) => onFilterChange('tollStation', e.target.value)}>
              <option value="Tất cả">Tất cả</option>
              <option value="Trạm Hà Nội">Trạm Hà Nội</option>
              <option value="Trạm Hồ Chí Minh">Trạm Hồ Chí Minh</option>
            </select>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="flex items-center gap-2">
            <label className={labelClass}>Từ ngày <span className="text-red-500">*</span></label>
            <input type="date" className={inputClass} value={filters.fromDate} onChange={(e) => onFilterChange('fromDate', e.target.value)} />
          </div>
          <div className="flex items-center gap-2">
            <label className={labelClass}>Đến ngày <span className="text-red-500">*</span></label>
            <input type="date" className={inputClass} value={filters.toDate} onChange={(e) => onFilterChange('toDate', e.target.value)} />
          </div>
          <div className="flex items-center gap-2">
            <label className={labelClass}>Trạng thái xác minh</label>
            <select className={selectClass} value={filters.verificationStatus} onChange={(e) => onFilterChange('verificationStatus', e.target.value)}>
              <option value="Tất cả">Tất cả</option>
              <option value="Chờ xác minh">Chờ xác minh</option>
              <option value="Đã xác minh">Đã xác minh</option>
              <option value="Không đạt">Không đạt</option>
            </select>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 pt-2 border-t border-slate-100">
          <div className="flex items-center gap-2 relative" ref={statusRef}>
            <label className="text-[12px] text-emerald-700 w-[120px] shrink-0 font-bold">Trạng thái đơn</label>
            <div className={`${selectClass} flex items-center bg-white`} onClick={() => setIsStatusOpen(!isStatusOpen)}>
              <span className="truncate">{getMultiLabel(filters.orderStatus)}</span>
            </div>
            {isStatusOpen && (
              <div className="absolute top-full left-[120px] right-0 mt-1 bg-white border border-slate-200 rounded-lg shadow-xl z-[100] p-2 space-y-1">
                <div className={`flex items-center gap-2 px-2 py-1.5 rounded cursor-pointer hover:bg-slate-50 ${filters.orderStatus.includes('Tất cả') ? 'bg-emerald-50 text-emerald-700 font-bold' : ''}`} onClick={() => toggleOrderStatus('Tất cả')}>
                  <div className={`w-3.5 h-3.5 border rounded ${filters.orderStatus.includes('Tất cả') ? 'bg-emerald-500 border-emerald-500' : 'bg-white border-slate-300'}`}></div>
                  <span className="text-[11px]">Tất cả</span>
                </div>
                {orderStatusOptions.map(opt => (
                  <div key={opt.value} className={`flex items-center gap-2 px-2 py-1.5 rounded cursor-pointer hover:bg-slate-50 ${filters.orderStatus.includes(opt.value) ? 'bg-emerald-50 text-emerald-700 font-bold' : ''}`} onClick={() => toggleOrderStatus(opt.value)}>
                    <div className={`w-3.5 h-3.5 border rounded ${filters.orderStatus.includes(opt.value) ? 'bg-emerald-500 border-emerald-500' : 'bg-white border-slate-300'}`}></div>
                    <span className="text-[11px]">{opt.label}</span>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="flex items-center gap-2 relative" ref={requestRef}>
            <label className="text-[12px] text-emerald-700 w-[120px] shrink-0 font-bold">Trạng thái yêu cầu</label>
            <div className={`${selectClass} flex items-center bg-white`} onClick={() => setIsRequestOpen(!isRequestOpen)}>
              <span className="truncate">{getMultiLabel(filters.requestStatus, 'REQUEST')}</span>
            </div>
            {isRequestOpen && (
              <div className="absolute top-full left-[120px] right-0 mt-1 bg-white border border-slate-200 rounded-lg shadow-xl z-[100] p-2 space-y-1 max-h-[300px] overflow-y-auto scrollbar-thin">
                <div className={`flex items-center gap-2 px-2 py-1.5 rounded cursor-pointer hover:bg-slate-50 ${filters.requestStatus.includes('Tất cả') ? 'bg-emerald-50 text-emerald-700 font-bold' : ''}`} onClick={() => toggleRequestStatus('Tất cả')}>
