        supporter: currentUser,
        orderStatus: ['INITIAL'],
        requestStatus: ['Tất cả']
      }));
    }
  };

  const handleNotSupported = () => {
    if (userRole === 'OSA') {
      setFilters(prev => ({
        ...prev,
        supporter: 'NONE',
        orderStatus: ['INITIAL', 'CONFIRMED', 'ASSIGNING', 'IN_PROGRESS'],
        requestStatus: ['Tất cả']
      }));
    } else {
      setFilters(prev => ({
        ...prev,
        supporter: 'NONE',
        orderStatus: ['INITIAL'],
        requestStatus: ['Tất cả']
      }));
    }
  };

  const applyFilters = () => {
    let result = [...orders];
    if (filters.supporter === 'NONE') {
      result = result.filter(o => (!o.cskhName || o.cskhName === '---' || o.cskhName === '') && (!o.osaName || o.osaName === '---' || o.osaName === ''));
    } else if (filters.supporter !== 'Tất cả') {
      result = result.filter(o => o.createdBy === filters.supporter || o.updatedBy === filters.supporter || o.cskhName === filters.supporter || o.osaName === filters.supporter);
    }
    if (filters.orderCode) result = result.filter(o => o.orderCode.toLowerCase().includes(filters.orderCode.toLowerCase()));
    if (filters.phone) result = result.filter(o => o.customer.phone.includes(filters.phone));
    if (filters.plate) result = result.filter(o => o.vehicle.plate.toLowerCase().includes(filters.plate.toLowerCase()));
    if (!filters.orderStatus.includes('Tất cả') && filters.orderStatus.length > 0) {
      result = result.filter(o => filters.orderStatus.includes(o.orderStatus));
    }
    if (!filters.requestStatus.includes('Tất cả') && filters.requestStatus.length > 0) {
      result = result.filter(o => filters.requestStatus.includes(o.requestStatus));
    }
    if (filters.verificationStatus !== 'Tất cả') {
      result = result.filter(o => o.verificationStatus === filters.verificationStatus);
    }
    if (filters.service !== 'Tất cả') {
      result = result.filter(o => o.service.some(s => s.includes(filters.service)));
    }
    setFilteredOrders(result);
  };

  const handleOrderAction = (order: Order) => {
    const cskh = order.cskhName || '---';
    const osa = order.osaName || '---';

    // Logic 1: If assigned to current user (either role), go to detail
    if (cskh === currentUser || osa === currentUser) {
      alert(`Chuyển đến màn hình chi tiết đơn hàng: ${order.orderCode}`);
      return;
    }

    // Logic 2: If unassigned in the context of the user's role
    const isUnassigned = (cskh === '---' || cskh === '') && (osa === '---' || osa === '');
    if (isUnassigned) {
      if (userRole === 'CSKH') {
        setSelectedOrderForSupport(order);
      } else {
        setSelectedOrderForAssign(order);
      }
      return;
    }

    // Logic 3: If already partially assigned but current user wants to step in (OSA can assign anyone)
    if (userRole === 'OSA') {
        setSelectedOrderForAssign(order);
        return;
    }

    console.warn("Order is handled by someone else.");
  };

  const handleAssignConfirm = (orderId: string, assignedTo: string) => {
    const updatedOrders = orders.map(o => {
      if (o.id === orderId) {
        // Update the specific field based on user role or logic
        if (userRole === 'CSKH') {
          return { ...o, cskhName: assignedTo, updatedBy: assignedTo, updatedAt: new Date().toLocaleString('vi-VN').replace(',', ' -') };
        } else {
          return { ...o, osaName: assignedTo, updatedBy: assignedTo, updatedAt: new Date().toLocaleString('vi-VN').replace(',', ' -') };
        }
      }
      return o;
    });
    setOrders(updatedOrders);
    setSelectedOrderForAssign(null);
    setSelectedOrderForSupport(null);
  };

  const handleVerifyResult = (orderId: string, status: VerificationStatus) => {
    const updatedOrders = orders.map(o => 
      o.id === orderId ? { ...o, verificationStatus: status, updatedBy: currentUser, updatedAt: new Date().toLocaleString('vi-VN').replace(',', ' -') } : o
    );
    setOrders(updatedOrders);
    setSelectedOrderForVerify(null);
  };

  const handleAcceptSupportFromSupervision = (orderId: string) => {
    setSupervisionOrders(prev => prev.map(o => 
      o.id === orderId ? { ...o, isInActiveSupport: true, status: 'SearchingPartner' } : o
    ));
    setConfirmSupportOrder(null);
  };

  useEffect(() => {
    applyFilters();
  }, [filters, orders]);

  const getBreadcrumbs = () => {
    const base = {
      ORDER_MANAGEMENT: { parent: 'Chăm sóc khách hàng', page: 'Quản lý đơn hàng' },
      RESCUE_SUPERVISION: { parent: 'Giám sát cứu hộ', page: 'Giám sát' },
      ACTIVE_SUPPORT: { parent: 'Giám sát cứu hộ', page: 'Đang hỗ trợ' }
    };
    return base[currentView];
  };

  return (
    <div className="flex h-screen overflow-hidden bg-[#f8fafc]">
      <Sidebar isOpen={isSidebarOpen} toggle={() => setIsSidebarOpen(!isSidebarOpen)} currentView={currentView} onViewChange={setCurrentView} userRole={userRole} currentUser={currentUser} />
      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 z-10">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-400 hover:bg-slate-50 rounded-lg"><svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16m-7 6h7" /></svg></button>
            <h1 className="text-[15px] font-bold text-slate-800 uppercase tracking-tight">VETC - CỔNG THÔNG TIN DÀNH CHO ĐẠI LÝ</h1>
          </div>
          <div className="flex items-center gap-6">
            <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200 shadow-inner">
              <button onClick={() => handleRoleSwitch('CSKH')} className={`px-4 py-1.5 rounded-lg text-[11px] font-black transition-all uppercase tracking-wider ${userRole === 'CSKH' ? 'bg-[#00a651] text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>CSKH</button>
              <button onClick={() => handleRoleSwitch('OSA')} className={`px-4 py-1.5 rounded-lg text-[11px] font-black transition-all uppercase tracking-wider ${userRole === 'OSA' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>OSA</button>
            </div>
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2 cursor-pointer hover:bg-slate-50 p-2 rounded-lg">
                <div className={`px-2 py-0.5 rounded text-[10px] font-black text-white ${userRole === 'CSKH' ? 'bg-emerald-600' : 'bg-indigo-600'}`}>{userRole}</div>
                <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center border-2 border-white shadow-sm overflow-hidden"><svg className="w-5 h-5 text-slate-400" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" /></svg></div>
                <div className="flex flex-col"><span className="text-[13px] font-bold text-slate-700 leading-none">{currentUser}</span></div>
              </div>
            </div>
          </div>
        </header>
        <div className="bg-[#00a651] px-6 py-2.5 flex items-center justify-between text-white text-[12px] font-medium shrink-0 shadow-sm">
          <div className="flex items-center gap-3">
            <div className="w-5 h-5 bg-white/20 rounded flex items-center justify-center"><svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 20 20"><path d="M10.707 2.293a1 1 0 00-1.414 0l-7 7a1 1 0 001.414 1.414L4 10.414V17a1 1 0 001 1h2a1 1 0 001-1v-2a1 1 0 011-1h2a1 1 0 011 1v2a1 1 0 001 1h2a1 1 0 001-1v-6.586l.293.293a1 1 0 001.414-1.414l-7-7z" /></svg></div>
            <span className="opacity-80">Trang chủ</span><span>&gt;</span><span className="opacity-80 uppercase font-bold">{getBreadcrumbs().parent}</span><span>&gt;</span><span className="font-bold uppercase">{getBreadcrumbs().page}</span>
          </div>
          <div className="flex items-center gap-4 text-[11px] font-bold">
            <div className="flex items-center gap-2"><span className={`px-2 py-0.5 rounded text-[9px] text-white ${userRole === 'CSKH' ? 'bg-emerald-700' : 'bg-indigo-700'}`}>{userRole}</span><span className="bg-white/10 px-2.5 py-1 rounded">{currentUser}</span></div>
            <span>{currentTime.split(' ')[0]}</span>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto scrollbar-thin">
          {currentView === 'ORDER_MANAGEMENT' && (
            <div className="p-4 space-y-4">
              <FilterPanel 
                filters={filters} 
                onFilterChange={handleFilterChange} 
                onSearch={applyFilters} 
                onMySupport={handleMySupport}
                onNotSupported={handleNotSupported}
                userRole={userRole}
              />
              <OrderTable 
                orders={filteredOrders} 
                onVerifyClick={handleOrderAction}
                currentUser={currentUser}
                userRole={userRole}
              />
            </div>
          )}
          {currentView === 'RESCUE_SUPERVISION' && <SupervisionDashboard orders={supervisionOrders} onAcceptSupport={(order) => setConfirmSupportOrder(order)} />}
          {currentView === 'ACTIVE_SUPPORT' && <ActiveSupportDashboard orders={supervisionOrders} onAcceptSupport={(order) => setConfirmSupportOrder(order)} />}
        </div>
      </main>

      {/* Modals */}
      {selectedOrderForVerify && (
        <VerifyModal 
          order={selectedOrderForVerify} 
          onClose={() => setSelectedOrderForVerify(null)} 
          onConfirm={(status) => handleVerifyResult(selectedOrderForVerify.id, status)} 
        />
      )}

      {selectedOrderForSupport && (
        <SupportConfirmModal 
          order={{
            id: selectedOrderForSupport.id,
            orderCode: selectedOrderForSupport.orderCode,
            customerName: selectedOrderForSupport.customer.name,
            plate: selectedOrderForSupport.vehicle.plate,
            location: selectedOrderForSupport.address,
            services: selectedOrderForSupport.service,
            status: 'Searching',
            phone: selectedOrderForSupport.customer.phone,
            waitTime: '0p'
          }} 
          onClose={() => setSelectedOrderForSupport(null)} 
          onConfirm={() => handleAssignConfirm(selectedOrderForSupport.id, currentUser)} 
        />
      )}

      {selectedOrderForAssign && (
        <AssignModal
          order={selectedOrderForAssign}
          onClose={() => setSelectedOrderForAssign(null)}
          onConfirm={(userId) => handleAssignConfirm(selectedOrderForAssign.id, userId)}
          currentUser={currentUser}
        />
      )}

      {confirmSupportOrder && (
        <SupportConfirmModal 
          order={confirmSupportOrder} 
          onClose={() => setConfirmSupportOrder(null)} 
          onConfirm={() => handleAcceptSupportFromSupervision(confirmSupportOrder.id)} 
        />
      )}
    </div>
  );
};

export default App;

export type OrderStatusKey = 'INITIAL' | 'CONFIRMED' | 'ASSIGNING' | 'IN_PROGRESS' | 'COMPLETED' | 'FAILED' | 'Tất cả';
export type VerificationStatus = 'Chờ xác minh' | 'Đã xác minh' | 'Không đạt' | 'Tất cả';

export type AppView = 'ORDER_MANAGEMENT' | 'RESCUE_SUPERVISION' | 'ACTIVE_SUPPORT' | 'ORDER_DETAIL';
export type UserRole = 'CSKH' | 'OSA';

export interface Order {
  id: string;
  orderCode: string;
  service: string[];
  quantity: number;
  providerFee: number;
  requestStatus: string;
  orderStatus: string;
  verificationStatus: VerificationStatus;
  customer: {
    name: string;
    phone: string;
  };
  vehicle: {
    plate: string;
    brand: string;
    model: string;
  };
  address: string;
  createdAt: string;
  createdBy: string;
  updatedAt: string;
  updatedBy: string;
  cskhName?: string;
  osaName?: string;
  typeBadge: 'Đơn lẻ' | 'Đơn gói';
  sourceBadge: 'PORTAL' | 'ECOM';
  supportPartner?: string;
  driver?: {
    name: string;
    phone: string;
  };
  partnerVehicle?: {
    plate: string;
    brand: string;
    model: string;
  };
  rescueStation?: string;
  stationAddress?: string;
  towToLocation?: string;
}

export interface SupervisionOrder {
  id: string;
  orderCode: string;
  fullCode?: string;
  customerName: string;
  phone: string;
  plate: string;
  vehicleModel?: string;
  location: string;
  services: string[];
  waitTime: string;
  status: 'Searching' | 'NoStation' | 'Assigned' | 'Expired' | 'MissingInfo' | 'SearchingPartner' | 'Repairing' | 'WaitingConfirm';
  isUrgent?: boolean;
  isInActiveSupport?: boolean;
}

export interface SupervisionFilterState {
  status: string;
  location: string;
  waitFrom: string;
  waitTo: string;
}

export interface FilterState {
  orderCode: string;
  phone: string;
  plate: string;
  service: string;
  partner: string;
  tollStation: string;
  orderStatus: string[]; 
  requestStatus: string[];
  verificationStatus: string;
  supporter: string;
  fromDate: string;
  toDate: string;
}

import React, { useState, useEffect } from 'react';
import { Order, UserRole } from '../types';

interface OrderTableProps {
  orders: Order[];
  onVerifyClick: (order: Order) => void;
  onDetailClick: (order: Order) => void;
  currentUser: string;
  userRole: UserRole;
}

const OrderTable: React.FC<OrderTableProps> = ({ orders, onVerifyClick, onDetailClick, currentUser, userRole }) => {
  const [now, setNow] = useState(new Date());

  // Update the "now" reference every second to refresh wait times
  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const parseDateStr = (dateStr: string) => {
    if (!dateStr || dateStr === '---') return null;
    try {
      const [datePart, timePart] = dateStr.split(' - ');
      const [day, month, year] = datePart.split('/').map(Number);
      const [hour, min, sec] = timePart.split(':').map(Number);
      return new Date(year, month - 1, day, hour, min, sec);
    } catch (e) {
      return null;
    }
  };

  const calculateWaitTime = (order: Order) => {
    const createdDate = parseDateStr(order.createdAt);
    if (!createdDate) return '---';

    // Countdown logic based on status
    const isLive = ['INITIAL', 'CONFIRMED', 'ASSIGNING'].includes(order.orderStatus);

    // If live, compare to current time. If fixed, compare to last updated time.
    const endTime = isLive ? now : (parseDateStr(order.updatedAt) || now);

    const diffMs = endTime.getTime() - createdDate.getTime();
    if (diffMs < 0) return '0p';

    const totalSeconds = Math.floor(diffMs / 1000);
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;

    if (minutes >= 60) {
      const hours = Math.floor(minutes / 60);
      return `${hours}h ${minutes % 60}p`;
    }
    return `${minutes}p ${seconds}s`;
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'INITIAL':
        return <span className="px-2 py-0.5 bg-blue-50 text-blue-600 rounded-full font-bold border border-blue-100 uppercase text-[9px]">Khởi tạo</span>;
      case 'CONFIRMED':
        return <span className="px-2 py-0.5 bg-emerald-50 text-emerald-600 rounded-full font-bold border border-emerald-100 uppercase text-[9px]">Xác nhận</span>;
      case 'ASSIGNING':
        return <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 rounded-full font-bold border border-indigo-100 uppercase text-[9px]">Điều phối</span>;
      case 'IN_PROGRESS':
        return <span className="px-2 py-0.5 bg-amber-50 text-amber-600 rounded-full font-bold border border-amber-100 uppercase text-[9px]">Đang xử lý</span>;
      case 'COMPLETED':
        return <span className="px-2 py-0.5 bg-slate-50 text-slate-500 rounded-full font-bold border border-slate-200 uppercase text-[9px]">Hoàn thành</span>;
      case 'FAILED':
        return <span className="px-2 py-0.5 bg-red-50 text-red-600 rounded-full font-bold border border-red-100 uppercase text-[9px]">Thất bại</span>;
      default:
        return <span className="text-slate-400 italic text-[10px]">{status}</span>;
    }
  };

  const isAssignedToOthers = (order: Order) => {
    const cskh = order.cskhName || '---';
    const osa = order.osaName || '---';
    // If it's assigned and neither is the current user, it's assigned to someone else
    const isUnassigned = (cskh === '---' || cskh === '') && (osa === '---' || osa === '');
    if (isUnassigned) return false;
    return cskh !== currentUser && osa !== currentUser;
  };

  const getActionTitle = (order: Order) => {
    if (isAssignedToOthers(order)) return `Đang được hỗ trợ bởi ${order.cskhName || order.osaName}`;
    const cskh = order.cskhName || '---';
    const osa = order.osaName || '---';
    if ((cskh === '---' || cskh === '') && (osa === '---' || osa === '')) {
      return userRole === 'CSKH' ? "Nhận hỗ trợ đơn này" : "Phân công hỗ trợ đơn này";
    }
    return "Xem chi tiết đơn hàng";
  };

  return (
    <div className="bg-white border border-emerald-500 rounded overflow-hidden flex flex-col mb-4 shadow-sm">
      <div className="bg-[#00a651] px-4 py-2 flex items-center justify-between">
        <h3 className="text-white font-bold text-sm uppercase tracking-wider">Danh sách đơn cứu hộ</h3>
        <span className="text-white/70 text-[10px] font-medium">{orders.length} kết quả</span>
      </div>

      <div className="overflow-x-auto scrollbar-thin">
        <table className="w-full text-left border-collapse min-w-[2150px]">
          <thead>
            <tr className="bg-slate-50 text-slate-500 text-[10px] font-bold uppercase tracking-wider">
              <th rowSpan={2} className="border p-3 w-12 text-center sticky left-0 bg-slate-50 z-20">STT</th>
              <th rowSpan={2} className="border p-3 w-32 text-center sticky left-12 bg-slate-50 z-20">Thao tác</th>
              <th colSpan={5} className="border p-3 w-40 text-center">Thông tin đơn hàng</th>
              <th colSpan={3} className="border p-3 w-48 text-center">Thông tin khách hàng</th>
              <th colSpan={3} className="border p-3 w-36 text-center">Thông tin đối tác hỗ trợ</th>
              <th colSpan={2} className="border p-3 w-32 text-center">Thông tin hệ thống</th>
            </tr>
            <tr className="bg-slate-50 text-slate-500 text-[10px] font-bold uppercase tracking-wider">
              <th className="border p-3 w-40 text-center">Mã đơn hàng</th>
              <th className="border p-3 w-48 text-center">Dịch vụ</th>
              <th className="border p-3 w-32 text-center">Thời gian chờ</th>
              <th className="border p-3 w-36 text-center">Trạng thái</th>
              <th className="border p-3 w-40 text-center">Người hỗ trợ</th>
              <th className="border p-3 w-48 text-center">Khách hàng</th>
              <th className="border p-3 w-40 text-center">Xe</th>
              <th className="border p-3 w-64 text-center">Địa chỉ cứu hộ</th>
              <th className="border p-3 w-40 text-center">Đối tác</th>
              <th className="border p-3 w-40 text-center">Tài xế</th>
              <th className="border p-3 w-48 text-center">Điểm xử lý</th>
              <th className="border p-3 w-44 text-center">Ngày tạo</th>
              <th className="border p-3 w-32 text-center">Người tạo</th>
            </tr>
          </thead>
          <tbody className="text-[11px] text-slate-700 bg-white">
            {orders.length > 0 ? orders.map((order, idx) => {
              const disabled = isAssignedToOthers(order);
              const waitTime = calculateWaitTime(order);
              const isWaitingStatus = ['INITIAL', 'CONFIRMED', 'ASSIGNING'].includes(order.orderStatus);

              return (
                <tr key={order.id} className="hover:bg-slate-50 border-b last:border-b-0 group">
                  <td className="border-r p-3 text-center font-medium text-slate-400 sticky left-0 bg-white group-hover:bg-slate-50 z-10">
                    {idx + 1}
                  </td>
                  <td className="border-r p-3 sticky left-12 bg-white group-hover:bg-slate-50 z-10">
                    <div className="flex items-center justify-center gap-3">
                      <button 
                        onClick={() => onDetailClick(order)}
                        className="p-1.5 text-slate-400 hover:text-blue-500 hover:bg-blue-50 rounded transition-colors" title="Xem chi tiết">
                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                        </svg>
                      </button>

                      <button 
                        disabled={disabled}
                        onClick={() => onVerifyClick(order)}
                        title={getActionTitle(order)}
                        className={`p-1.5 rounded transition-all ${disabled ? 'text-slate-200 cursor-not-allowed opacity-30' : 'text-emerald-600 hover:bg-emerald-50 hover:scale-110 active:scale-95'}`}
                      >
                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                        </svg>
                      </button>
                    </div>
                  </td>
                  <td className="border-r p-3">
                    <div className="flex flex-col gap-1">
                      <span className="font-bold text-slate-900">{order.orderCode}</span>
                      <div className="flex gap-1">
                        <span className="px-1 py-0.5 rounded-[2px] bg-blue-50 text-blue-500 text-[8px] font-black uppercase border border-blue-100">{order.typeBadge}</span>
                        <span className="px-1 py-0.5 rounded-[2px] bg-emerald-50 text-emerald-500 text-[8px] font-black uppercase border border-emerald-100">{order.sourceBadge}</span>
                      </div>
                    </div>
                  </td>
                  <td className="border-r p-3">
                    <div className="flex flex-wrap gap-1">
                      {order.service.map((s, i) => (
                        <span key={i} className="px-1.5 py-0.5 bg-slate-50 text-slate-600 rounded border border-slate-100 font-medium whitespace-nowrap">
                          {s}
                        </span>
                      ))}
                    </div>
                  </td>
                  <td className="border-r p-3 text-center">
                    <span className={`font-black text-[12px] tracking-tight ${!isWaitingStatus ? 'text-slate-400' : (waitTime.includes('h') ? 'text-red-500' : 'text-slate-700')}`}>
                      {waitTime}
                    </span>
                  </td>
                  <td className="border-r p-3">
                    <div className="flex flex-col gap-1.5">
                      {getStatusBadge(order.orderStatus)}
                      <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded w-fit ${order.verificationStatus === 'Đã xác minh' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-500'}`}>
                        {order.verificationStatus}
                      </span>
                    </div>
                  </td>
