import React, { useState, useEffect } from 'react';
import { Order, UserRole } from '../types';

interface OrderTableProps {
  orders: Order[];
  onVerifyClick: (order: Order) => void;
  onDetailClick: (order: Order) => void;
  currentUser: string;
  userRole: UserRole;
}

const OrderTable: React.FC<OrderTableProps> = ({ orders, onVerifyClick, onDetailClick, currentUser, userRole }) => {
  const [now, setNow] = useState(new Date());

  // Update the "now" reference every second to refresh wait times
  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const parseDateStr = (dateStr: string) => {
    if (!dateStr || dateStr === '---') return null;
    try {
      const [datePart, timePart] = dateStr.split(' - ');
      const [day, month, year] = datePart.split('/').map(Number);
      const [hour, min, sec] = timePart.split(':').map(Number);
      return new Date(year, month - 1, day, hour, min, sec);
    } catch (e) {
      return null;
    }
  };

  const calculateWaitTime = (order: Order) => {
    const createdDate = parseDateStr(order.createdAt);
    if (!createdDate) return '---';

    // Countdown logic based on status
    const isLive = ['INITIAL', 'CONFIRMED', 'ASSIGNING'].includes(order.orderStatus);

    // If live, compare to current time. If fixed, compare to last updated time.
    const endTime = isLive ? now : (parseDateStr(order.updatedAt) || now);

    const diffMs = endTime.getTime() - createdDate.getTime();
    if (diffMs < 0) return '0p';

    const totalSeconds = Math.floor(diffMs / 1000);
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;

    if (minutes >= 60) {
      const hours = Math.floor(minutes / 60);
      return `${hours}h ${minutes % 60}p`;
    }
    return `${minutes}p ${seconds}s`;
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'INITIAL':
        return <span className="px-2 py-0.5 bg-blue-50 text-blue-600 rounded-full font-bold border border-blue-100 uppercase text-[9px]">Khởi tạo</span>;
      case 'CONFIRMED':
        return <span className="px-2 py-0.5 bg-emerald-50 text-emerald-600 rounded-full font-bold border border-emerald-100 uppercase text-[9px]">Xác nhận</span>;
      case 'ASSIGNING':
        return <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 rounded-full font-bold border border-indigo-100 uppercase text-[9px]">Điều phối</span>;
      case 'IN_PROGRESS':
        return <span className="px-2 py-0.5 bg-amber-50 text-amber-600 rounded-full font-bold border border-amber-100 uppercase text-[9px]">Đang xử lý</span>;
      case 'COMPLETED':
        return <span className="px-2 py-0.5 bg-slate-50 text-slate-500 rounded-full font-bold border border-slate-200 uppercase text-[9px]">Hoàn thành</span>;
      case 'FAILED':
        return <span className="px-2 py-0.5 bg-red-50 text-red-600 rounded-full font-bold border border-red-100 uppercase text-[9px]">Thất bại</span>;
      default:
        return <span className="text-slate-400 italic text-[10px]">{status}</span>;
    }
  };

  const isVerifyDisabled = (order: Order) => {
    const cskh = order.cskhName || '---';
    const osa = order.osaName || '---';

    if (userRole === 'CSKH') {
      // Disabled if cskh is assigned to someone else
      return (cskh !== '---' && cskh !== '' && cskh !== currentUser);
    } else {
      // OSA Role
      // Disabled if osa is assigned to someone else
      return (osa !== '---' && osa !== '' && osa !== currentUser);
    }
  };

  const getActionTitle = (order: Order) => {
    const cskh = order.cskhName || '---';
    const osa = order.osaName || '---';

    if (userRole === 'CSKH') {
      if (cskh === '---' || cskh === '') return "Xác nhận hỗ trợ đơn này";
      if (cskh === currentUser) return "Thực hiện xác minh (Vào chi tiết)";
      return `Đang được hỗ trợ bởi CSKH ${cskh}`;
    } else {
      // OSA
      if (cskh === '---' || cskh === '') return "Phân công hỗ trợ cho CSKH";
      if (osa === currentUser) return "Xem chi tiết đơn đang giám sát";
      if (osa !== '---' && osa !== '') return `Đang được giám sát bởi OSA ${osa}`;
      return "Gán OSA hỗ trợ (Vào chi tiết)";
    }
  };

  return (
    <div className="bg-white border border-emerald-500 rounded overflow-hidden flex flex-col mb-4 shadow-sm">
      <div className="bg-[#00a651] px-4 py-2 flex items-center justify-between">
