    if (filters.orderCode) result = result.filter(o => o.orderCode.toLowerCase().includes(filters.orderCode.toLowerCase()));
    if (filters.phone) result = result.filter(o => o.customer.phone.includes(filters.phone));
    if (filters.plate) result = result.filter(o => o.vehicle.plate.toLowerCase().includes(filters.plate.toLowerCase()));

    // Lọc theo Trạng thái đơn
    if (!filters.orderStatus.includes('Tất cả') && filters.orderStatus.length > 0) {
      result = result.filter(o => filters.orderStatus.includes(o.orderStatus));
    }

    // Lọc theo Trạng thái yêu cầu
    if (!filters.requestStatus.includes('Tất cả') && filters.requestStatus.length > 0) {
      result = result.filter(o => filters.requestStatus.includes(o.requestStatus));
    }

    if (filters.verificationStatus !== 'Tất cả') {
      result = result.filter(o => o.verificationStatus === filters.verificationStatus);
    }

    if (filters.service !== 'Tất cả') {
      result = result.filter(o => o.service.some(s => s.includes(filters.service)));
    }

    setFilteredOrders(result);
  };

  const handleOrderAction = (order: Order) => {
    const cskh = order.cskhName || '---';
    const osa = order.osaName || '---';

    if (userRole === 'CSKH') {
      if (cskh === '---' || cskh === '') {
        setSelectedOrderForSupport(order);
      } else if (cskh === currentUser) {
        handleGoToDetail(order, true); // Verify icon click -> Editable
      }
    } else {
      if (cskh === '---' || cskh === '') {
        setSelectedOrderForAssign(order);
      } else if (osa === currentUser) {
        handleGoToDetail(order, true); // Verify icon click -> Editable
      } else if (osa === '---' || osa === '') {
        handleGoToDetail(order, true); 
      }
    }
  };

  const handleGoToDetail = (order: Order, isEditMode: boolean) => {
    setSelectedOrderForDetail(order);
    setDetailEditMode(isEditMode);
    setCurrentView('ORDER_DETAIL');
  };

  const handleAssignConfirm = (orderId: string, assignedTo: string) => {
    const updatedOrders = orders.map(o => {
      if (o.id === orderId) {
        const timestamp = new Date().toLocaleString('vi-VN').replace(',', ' -');
        if (userRole === 'CSKH') {
          return { 
            ...o, 
            cskhName: assignedTo, 
            updatedBy: assignedTo, 
            updatedAt: timestamp 
          };
        } else {
          return { 
            ...o, 
            cskhName: assignedTo, 
            osaName: o.osaName === currentUser ? o.osaName : (o.osaName === '---' || o.osaName === '' ? currentUser : o.osaName),
            updatedBy: currentUser, 
            updatedAt: timestamp 
          };
        }
      }
      return o;
    });
    setOrders(updatedOrders);
    setSelectedOrderForAssign(null);
    setSelectedOrderForSupport(null);

    const updatedOrder = updatedOrders.find(o => o.id === orderId);
    if (updatedOrder && (updatedOrder.cskhName === currentUser || updatedOrder.osaName === currentUser)) {
       handleGoToDetail(updatedOrder, true);
    }
  };

  const handleSaveOrder = (updatedOrder: Order) => {
    setOrders(prev => prev.map(o => o.id === updatedOrder.id ? updatedOrder : o));
    console.log("Order saved:", updatedOrder.orderCode);
  };

  const handleVerifyResult = (orderId: string, status: VerificationStatus) => {
    const updatedOrders = orders.map(o => 
      o.id === orderId ? { ...o, verificationStatus: status, updatedBy: currentUser, updatedAt: new Date().toLocaleString('vi-VN').replace(',', ' -') } : o
    );
    setOrders(updatedOrders);
    setSelectedOrderForVerify(null);
  };

  const handleAcceptSupportFromSupervision = (orderId: string) => {
    setSupervisionOrders(prev => prev.map(o => 
      o.id === orderId ? { ...o, isInActiveSupport: true, status: 'SearchingPartner' } : o
    ));
    setConfirmSupportOrder(null);
  };

  useEffect(() => {
    applyFilters();
  }, [filters, orders, userRole]); // Thêm userRole vào deps để apply lại filter khi đổi role

  const getBreadcrumbs = () => {
    const base = {
      ORDER_MANAGEMENT: { parent: 'Chăm sóc khách hàng', page: 'Quản lý đơn hàng' },
      RESCUE_SUPERVISION: { parent: 'Giám sát cứu hộ', page: 'Giám sát' },
      ACTIVE_SUPPORT: { parent: 'Giám sát cứu hộ', page: 'Đang hỗ trợ' },
      ORDER_DETAIL: { parent: 'Chăm sóc khách hàng', page: 'Chi tiết đơn hàng' }
    };
    return base[currentView];
  };

  return (
    <div className="flex h-screen overflow-hidden bg-[#f8fafc]">
      <Sidebar isOpen={isSidebarOpen} toggle={() => setIsSidebarOpen(!isSidebarOpen)} currentView={currentView} onViewChange={setCurrentView} userRole={userRole} currentUser={currentUser} />
      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 z-10">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-400 hover:bg-slate-50 rounded-lg"><svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16m-7 6h7" /></svg></button>
            <h1 className="text-[15px] font-bold text-slate-800 uppercase tracking-tight">VETC - CỔNG THÔNG TIN DÀNH CHO ĐẠI LÝ</h1>
          </div>
          <div className="flex items-center gap-6">
            <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200 shadow-inner">
              <button onClick={() => handleRoleSwitch('CSKH')} className={`px-4 py-1.5 rounded-lg text-[11px] font-black transition-all uppercase tracking-wider ${userRole === 'CSKH' ? 'bg-[#00a651] text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>CSKH</button>
              <button onClick={() => handleRoleSwitch('OSA')} className={`px-4 py-1.5 rounded-lg text-[11px] font-black transition-all uppercase tracking-wider ${userRole === 'OSA' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>OSA</button>
            </div>
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2 cursor-pointer hover:bg-slate-50 p-2 rounded-lg">
                <div className={`px-2 py-0.5 rounded text-[10px] font-black text-white ${userRole === 'CSKH' ? 'bg-emerald-600' : 'bg-indigo-600'}`}>{userRole}</div>
                <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center border-2 border-white shadow-sm overflow-hidden"><svg className="w-5 h-5 text-slate-400" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" /></svg></div>
                <div className="flex flex-col"><span className="text-[13px] font-bold text-slate-700 leading-none">{currentUser}</span></div>
              </div>
            </div>
          </div>
        </header>
        <div className="bg-[#00a651] px-6 py-2.5 flex items-center justify-between text-white text-[12px] font-medium shrink-0 shadow-sm">
          <div className="flex items-center gap-3">
            <div className="w-5 h-5 bg-white/20 rounded flex items-center justify-center"><svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 20 20"><path d="M10.707 2.293a1 1 0 00-1.414 0l-7 7a1 1 0 001.414 1.414L4 10.414V17a1 1 0 001 1h2a1 1 0 001-1v-2a1 1 0 011-1h2a1 1 0 011 1v2a1 1 0 001 1h2a1 1 0 001-1v-6.586l.293.293a1 1 0 001.414-1.414l-7-7z" /></svg></div>
            <span className="opacity-80">Trang chủ</span><span>&gt;</span><span className="opacity-80 uppercase font-bold">{getBreadcrumbs().parent}</span><span>&gt;</span><span className="font-bold uppercase">{getBreadcrumbs().page}</span>
          </div>
          <div className="flex items-center gap-4 text-[11px] font-bold">
            <div className="flex items-center gap-2"><span className={`px-2 py-0.5 rounded text-[9px] text-white ${userRole === 'CSKH' ? 'bg-emerald-700' : 'bg-indigo-700'}`}>{userRole}</span><span className="bg-white/10 px-2.5 py-1 rounded">{currentUser}</span></div>
            <span>{currentTime.split(' ')[0]}</span>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto scrollbar-thin">
          {currentView === 'ORDER_MANAGEMENT' && (
            <div className="p-4 space-y-4">
              <FilterPanel 
                filters={filters} 
                onFilterChange={handleFilterChange} 
                onSearch={applyFilters} 
                onMySupport={handleMySupport}
                onNotSupported={handleNotSupported}
                userRole={userRole}
              />
              <OrderTable 
                orders={filteredOrders} 
                onVerifyClick={handleOrderAction}
                onDetailClick={(order) => handleGoToDetail(order, false)} 
                currentUser={currentUser}
                userRole={userRole}
              />
            </div>
          )}
          {currentView === 'RESCUE_SUPERVISION' && <SupervisionDashboard orders={supervisionOrders} onAcceptSupport={(order) => setConfirmSupportOrder(order)} />}
          {currentView === 'ACTIVE_SUPPORT' && <ActiveSupportDashboard orders={supervisionOrders} onAcceptSupport={(order) => setConfirmSupportOrder(order)} />}
          {currentView === 'ORDER_DETAIL' && selectedOrderForDetail && (
            <OrderDetail 
              order={selectedOrderForDetail} 
              initialEditMode={detailEditMode}
              onBack={() => {
                setSelectedOrderForDetail(null);
                setCurrentView('ORDER_MANAGEMENT');
              }} 
              onSave={handleSaveOrder}
            />
          )}
        </div>
      </main>

      {/* Modals */}
      {selectedOrderForVerify && (
        <VerifyModal 
          order={selectedOrderForVerify} 
          onClose={() => setSelectedOrderForVerify(null)} 
          onConfirm={(status) => handleVerifyResult(selectedOrderForVerify.id, status)} 
        />
      )}

      {selectedOrderForSupport && (
        <SupportConfirmModal 
          order={{
            id: selectedOrderForSupport.id,
            orderCode: selectedOrderForSupport.orderCode,
            customerName: selectedOrderForSupport.customer.name,
            plate: selectedOrderForSupport.vehicle.plate,
            location: selectedOrderForSupport.address,
            services: selectedOrderForSupport.service,
            status: 'Searching',
            phone: selectedOrderForSupport.customer.phone,
            waitTime: '0p'
          }} 
          onClose={() => setSelectedOrderForSupport(null)} 
          onConfirm={() => handleAssignConfirm(selectedOrderForSupport.id, currentUser)} 
        />
      )}

      {selectedOrderForAssign && (
        <AssignModal
          order={selectedOrderForAssign}
          onClose={() => setSelectedOrderForAssign(null)}
          onConfirm={(userId) => handleAssignConfirm(selectedOrderForAssign.id, userId)}
          currentUser={currentUser}
        />
      )}

      {confirmSupportOrder && (
        <SupportConfirmModal 
          order={confirmSupportOrder} 
          onClose={() => setConfirmSupportOrder(null)} 
          onConfirm={() => handleAcceptSupportFromSupervision(confirmSupportOrder.id)} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { FilterState, UserRole } from '../types';
import { STATUS_MAPPING, REQUEST_STATUS_LABELS } from '../constants';

interface FilterPanelProps {
  filters: FilterState;
  onFilterChange: (key: keyof FilterState, value: any) => void;
  onSearch: () => void;
  onMySupport: () => void;
  onNotSupported: () => void;
  onClear: () => void;
  userRole: UserRole;
}

const FilterPanel: React.FC<FilterPanelProps> = ({ filters, onFilterChange, onSearch, onMySupport, onNotSupported, onClear, userRole }) => {
  const [isStatusOpen, setIsStatusOpen] = useState(false);
  const [isRequestOpen, setIsRequestOpen] = useState(false);
  const statusRef = useRef<HTMLDivElement>(null);
  const requestRef = useRef<HTMLDivElement>(null);

  const orderStatusOptions = [
    { value: 'INITIAL', label: 'Khởi tạo (INITIAL)' },
    { value: 'CONFIRMED', label: 'Xác nhận (CONFIRMED)' },
    { value: 'ASSIGNING', label: 'Điều phối (ASSIGNING)' },
    { value: 'IN_PROGRESS', label: 'Đang thực hiện (IN_PROGRESS)' },
    { value: 'COMPLETED', label: 'Hoàn thành (COMPLETED)' },
    { value: 'FAILED', label: 'Thất bại (FAILED)' },
  ];

  const availableRequestStatuses = React.useMemo(() => {
    if (filters.orderStatus.includes('Tất cả')) {
      return Array.from(new Set(Object.values(STATUS_MAPPING).flat())).sort();
    }
    return Array.from(new Set(filters.orderStatus.flatMap(status => STATUS_MAPPING[status] || []))).sort();
  }, [filters.orderStatus]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (statusRef.current && !statusRef.current.contains(event.target as Node)) setIsStatusOpen(false);
      if (requestRef.current && !requestRef.current.contains(event.target as Node)) setIsRequestOpen(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleOrderStatus = (val: string) => {
    let next = [...filters.orderStatus];
    if (val === 'Tất cả') {
      next = ['Tất cả'];
    } else {
      next = next.filter(s => s !== 'Tất cả');
      if (next.includes(val)) {
        next = next.filter(s => s !== val);
        if (next.length === 0) next = ['Tất cả'];
      } else {
        next.push(val);
      }
    }
    onFilterChange('orderStatus', next);
    onFilterChange('requestStatus', ['Tất cả']);
  };

  const toggleRequestStatus = (val: string) => {
    let next = [...filters.requestStatus];
    if (val === 'Tất cả') {
      next = ['Tất cả'];
    } else {
      next = next.filter(s => s !== 'Tất cả');
      if (next.includes(val)) {
        next = next.filter(s => s !== val);
        if (next.length === 0) next = ['Tất cả'];
      } else {
        next.push(val);
      }
    }
    onFilterChange('requestStatus', next);
  };

  const labelClass = "text-[12px] text-slate-700 w-[120px] shrink-0 font-medium";
  const inputClass = "w-full px-3 py-1.5 bg-white border border-slate-200 rounded text-[12px] focus:outline-none focus:border-emerald-500 transition-colors";
  const selectClass = "w-full px-3 py-1.5 bg-white border border-slate-200 rounded text-[12px] focus:outline-none focus:border-emerald-500 appearance-none bg-[url('data:image/svg+xml;charset=US-ASCII,%3Csvg%20width%3D%2220%22%20height%3D%2220%22%20viewBox%3D%220%200%2020%2020%22%20fill%3D%22none%22%20xmlns%3D%22http%3A//www.w3.org/2000/svg%22%3E%3Cpath%20d%3D%22M5%207.5L10%2012.5L15%207.5%22%20stroke%3D%22%2394a3b8%22%20stroke-width%3D%221.5%22%20stroke-linecap%3D%22round%22%20stroke-linejoin%3D%22round%22/%3E%3C/svg%3E')] bg-[length:16px_16px] bg-no-repeat bg-[right_8px_center] transition-colors cursor-pointer";

  const getMultiLabel = (vals: string[], type: 'ORDER' | 'REQUEST' = 'ORDER') => {
    if (vals.includes('Tất cả')) return 'Tất cả';
    if (vals.length === 0) return 'Chọn...';
    if (vals.length === 1) {
      if (type === 'REQUEST') {
        const v = vals[0];
        return REQUEST_STATUS_LABELS[v] ? `${REQUEST_STATUS_LABELS[v]} (${v})` : v;
      }
      return vals[0];
    }
    return `Đã chọn ${vals.length}`;
  };

  return (
    <div className="bg-white border border-emerald-500 rounded shadow-sm relative z-30">
      <div className="bg-[#00a651] px-4 py-2 flex items-center gap-2 rounded-t-[3px]">
        <svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
        <h2 className="text-white text-[13px] font-bold uppercase tracking-wider">TRA CỨU ĐƠN HÀNG</h2>
      </div>

      <div className="p-6 space-y-4">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-x-12 gap-y-4">
          <div className="flex items-center gap-2">
            <label className={labelClass}>Mã đơn hàng</label>
            <input type="text" className={inputClass} value={filters.orderCode} onChange={(e) => onFilterChange('orderCode', e.target.value)} placeholder="Nhập mã đơn..." />
          </div>
          <div className="flex items-center gap-2">
            <label className={labelClass}>Số điện thoại</label>
            <input type="text" className={inputClass} value={filters.phone} onChange={(e) => onFilterChange('phone', e.target.value)} placeholder="09xx..." />
          </div>
          <div className="flex items-center gap-2">
            <label className={labelClass}>Biển số xe</label>
            <input type="text" className={inputClass} value={filters.plate} onChange={(e) => onFilterChange('plate', e.target.value)} placeholder="29A-xxxx..." />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-x-12 gap-y-4">
          <div className="flex items-center gap-2">
            <label className={labelClass}>Dịch vụ</label>
            <select className={selectClass} value={filters.service} onChange={(e) => onFilterChange('service', e.target.value)}>
              <option value="Tất cả">Tất cả</option>
              <option value="Kích bình ắc quy">Kích bình ắc quy</option>
              <option value="Thay lốp dự phòng">Thay lốp dự phòng</option>
              <option value="Cứu hộ kéo xe">Cứu hộ kéo xe</option>
            </select>
          </div>
          <div className="flex items-center gap-2">
            <label className={labelClass}>Đối tác</label>
            <select className={selectClass} value={filters.partner} onChange={(e) => onFilterChange('partner', e.target.value)}>
              <option value="Tất cả">Tất cả</option>
              <option value="CARPLA SERVICE">CARPLA SERVICE</option>
              <option value="RSA PARTNER">RSA PARTNER</option>
            </select>
          </div>
          <div className="flex items-center gap-2">
            <label className={labelClass}>Trạm cứu hộ</label>
            <select className={selectClass} value={filters.tollStation} onChange={(e) => onFilterChange('tollStation', e.target.value)}>
              <option value="Tất cả">Tất cả</option>
              <option value="Trạm Hà Nội">Trạm Hà Nội</option>
              <option value="Trạm Hồ Chí Minh">Trạm Hồ Chí Minh</option>
            </select>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="flex items-center gap-2">
            <label className={labelClass}>Từ ngày <span className="text-red-500">*</span></label>
            <input type="date" className={inputClass} value={filters.fromDate} onChange={(e) => onFilterChange('fromDate', e.target.value)} />
          </div>
          <div className="flex items-center gap-2">
            <label className={labelClass}>Đến ngày <span className="text-red-500">*</span></label>
            <input type="date" className={inputClass} value={filters.toDate} onChange={(e) => onFilterChange('toDate', e.target.value)} />
          </div>
          <div className="flex items-center gap-2">
            <label className={labelClass}>Trạng thái xác minh</label>
            <select className={selectClass} value={filters.verificationStatus} onChange={(e) => onFilterChange('verificationStatus', e.target.value)}>
              <option value="Tất cả">Tất cả</option>
              <option value="Chờ xác minh">Chờ xác minh</option>
              <option value="Đã xác minh">Đã xác minh</option>
              <option value="Không đạt">Không đạt</option>
            </select>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 pt-2 border-t border-slate-100">
          <div className="flex items-center gap-2 relative" ref={statusRef}>
            <label className="text-[12px] text-emerald-700 w-[120px] shrink-0 font-bold">Trạng thái đơn</label>
            <div className={`${selectClass} flex items-center bg-white`} onClick={() => setIsStatusOpen(!isStatusOpen)}>
              <span className="truncate">{getMultiLabel(filters.orderStatus)}</span>
            </div>
            {isStatusOpen && (
              <div className="absolute top-full left-[120px] right-0 mt-1 bg-white border border-slate-200 rounded-lg shadow-xl z-[100] p-2 space-y-1">
                <div className={`flex items-center gap-2 px-2 py-1.5 rounded cursor-pointer hover:bg-slate-50 ${filters.orderStatus.includes('Tất cả') ? 'bg-emerald-50 text-emerald-700 font-bold' : ''}`} onClick={() => toggleOrderStatus('Tất cả')}>
                  <div className={`w-3.5 h-3.5 border rounded ${filters.orderStatus.includes('Tất cả') ? 'bg-emerald-500 border-emerald-500' : 'bg-white border-slate-300'}`}></div>
                  <span className="text-[11px]">Tất cả</span>
                </div>
                {orderStatusOptions.map(opt => (
                  <div key={opt.value} className={`flex items-center gap-2 px-2 py-1.5 rounded cursor-pointer hover:bg-slate-50 ${filters.orderStatus.includes(opt.value) ? 'bg-emerald-50 text-emerald-700 font-bold' : ''}`} onClick={() => toggleOrderStatus(opt.value)}>
                    <div className={`w-3.5 h-3.5 border rounded ${filters.orderStatus.includes(opt.value) ? 'bg-emerald-500 border-emerald-500' : 'bg-white border-slate-300'}`}></div>
                    <span className="text-[11px]">{opt.label}</span>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="flex items-center gap-2 relative" ref={requestRef}>
            <label className="text-[12px] text-emerald-700 w-[120px] shrink-0 font-bold">Trạng thái yêu cầu</label>
            <div className={`${selectClass} flex items-center bg-white`} onClick={() => setIsRequestOpen(!isRequestOpen)}>
              <span className="truncate">{getMultiLabel(filters.requestStatus, 'REQUEST')}</span>
            </div>
            {isRequestOpen && (
              <div className="absolute top-full left-[120px] right-0 mt-1 bg-white border border-slate-200 rounded-lg shadow-xl z-[100] p-2 space-y-1 max-h-[300px] overflow-y-auto scrollbar-thin">
                <div className={`flex items-center gap-2 px-2 py-1.5 rounded cursor-pointer hover:bg-slate-50 ${filters.requestStatus.includes('Tất cả') ? 'bg-emerald-50 text-emerald-700 font-bold' : ''}`} onClick={() => toggleRequestStatus('Tất cả')}>
                  <div className={`w-3.5 h-3.5 border rounded ${filters.requestStatus.includes('Tất cả') ? 'bg-emerald-500 border-emerald-500' : 'bg-white border-slate-300'}`}></div>
                  <span className="text-[11px]">Tất cả</span>
                </div>
                {availableRequestStatuses.map(s => {
                  const label = REQUEST_STATUS_LABELS[s] ? `${REQUEST_STATUS_LABELS[s]} (${s})` : s;
                  return (
                    <div key={s} className={`flex items-center gap-2 px-2 py-1.5 rounded cursor-pointer hover:bg-slate-50 ${filters.requestStatus.includes(s) ? 'bg-emerald-50 text-emerald-700 font-bold' : ''}`} onClick={() => toggleRequestStatus(s)}>
                      <div className={`w-3.5 h-3.5 border rounded ${filters.requestStatus.includes(s) ? 'bg-emerald-500 border-emerald-500' : 'bg-white border-slate-300'}`}></div>
                      <span className="text-[11px] uppercase">{label}</span>
                    </div>
                  );
                })}
              </div>
            )}
          </div>

          <div className="flex items-center gap-3">
            <label className="text-[12px] text-emerald-700 font-bold shrink-0">Người hỗ trợ</label>
            <div className="flex items-center gap-2 flex-1">
              <select className={`${selectClass} border-emerald-300 flex-1`} value={filters.supporter} onChange={(e) => onFilterChange('supporter', e.target.value)}>
                <option value="Tất cả">Tất cả</option>
                <option value="NONE">Chưa hỗ trợ</option>
                <option value="rsa_test1">rsa_test1 (Tôi)</option>
