    if (filters.verificationStatus !== 'Tất cả') {
      result = result.filter(o => o.verificationStatus === filters.verificationStatus);
    }

    if (filters.service !== 'Tất cả') {
      result = result.filter(o => o.service.some(s => s.includes(filters.service)));
    }

    setFilteredOrders(result);
  };

  const handleOrderAction = (order: Order) => {
    const cskh = order.cskhName || '---';
    const osa = order.osaName || '---';

    if (userRole === 'CSKH') {
      if (cskh === '---' || cskh === '') {
        setSelectedOrderForSupport(order);
      } else if (cskh === currentUser) {
        handleGoToDetail(order, true); 
      }
    } else {
      if (cskh === '---' || cskh === '') {
        setSelectedOrderForAssign(order);
      } else if (osa === currentUser) {
        handleGoToDetail(order, true); 
      } else if (osa === '---' || osa === '') {
        handleGoToDetail(order, true); 
      }
    }
  };

  const handleGoToDetail = (order: Order, isEditMode: boolean) => {
    setSelectedOrderForDetail(order);
    setDetailEditMode(isEditMode);
    setCurrentView('ORDER_DETAIL');
  };

  const handleAssignConfirm = (orderId: string, assignedTo: string) => {
    const updatedOrders = orders.map(o => {
      if (o.id === orderId) {
        const timestamp = new Date().toLocaleString('vi-VN').replace(',', ' -');
        if (userRole === 'CSKH') {
          return { 
            ...o, 
            cskhName: assignedTo, 
            updatedBy: assignedTo, 
            updatedAt: timestamp 
          };
        } else {
          return { 
            ...o, 
            cskhName: assignedTo, 
            osaName: o.osaName === currentUser ? o.osaName : (o.osaName === '---' || o.osaName === '' ? currentUser : o.osaName),
            updatedBy: currentUser, 
            updatedAt: timestamp 
          };
        }
      }
      return o;
    });
    setOrders(updatedOrders);
    setSelectedOrderForAssign(null);
    setSelectedOrderForSupport(null);

    const updatedOrder = updatedOrders.find(o => o.id === orderId);
    if (updatedOrder && (updatedOrder.cskhName === currentUser || updatedOrder.osaName === currentUser)) {
       handleGoToDetail(updatedOrder, true);
    }
  };

  const handleSaveOrder = (updatedOrder: Order) => {
    setOrders(prev => prev.map(o => o.id === updatedOrder.id ? updatedOrder : o));
    console.log("Order saved:", updatedOrder.orderCode);
  };

  const handleVerifyResult = (orderId: string, status: VerificationStatus) => {
    const updatedOrders = orders.map(o => 
      o.id === orderId ? { ...o, verificationStatus: status, updatedBy: currentUser, updatedAt: new Date().toLocaleString('vi-VN').replace(',', ' -') } : o
    );
    setOrders(updatedOrders);
    setSelectedOrderForVerify(null);
  };

  const handleAcceptSupportFromSupervision = (orderId: string) => {
    setSupervisionOrders(prev => prev.map(o => 
      o.id === orderId ? { ...o, isInActiveSupport: true, status: 'SearchingPartner' } : o
    ));
    setConfirmSupportOrder(null);
  };

  useEffect(() => {
    applyFilters();
  }, [filters, orders, userRole]);

  const getBreadcrumbs = () => {
    const base = {
      ORDER_MANAGEMENT: { parent: 'Chăm sóc khách hàng', page: 'Quản lý đơn hàng' },
      RESCUE_SUPERVISION: { parent: 'Giám sát cứu hộ', page: 'Giám sát' },
      ACTIVE_SUPPORT: { parent: 'Giám sát cứu hộ', page: 'Đang hỗ trợ' },
      ORDER_DETAIL: { parent: 'Chăm sóc khách hàng', page: 'Chi tiết đơn hàng' }
    };
    return base[currentView];
  };

  return (
    <div className="flex h-screen overflow-hidden bg-[#f8fafc]">
      <Sidebar isOpen={isSidebarOpen} toggle={() => setIsSidebarOpen(!isSidebarOpen)} currentView={currentView} onViewChange={setCurrentView} userRole={userRole} currentUser={currentUser} />
      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 z-10">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-400 hover:bg-slate-50 rounded-lg"><svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16m-7 6h7" /></svg></button>
            <h1 className="text-[15px] font-bold text-slate-800 uppercase tracking-tight">VETC - CỔNG THÔNG TIN DÀNH CHO ĐẠI LÝ</h1>
          </div>
          <div className="flex items-center gap-6">
            <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200 shadow-inner">
              <button onClick={() => handleRoleSwitch('CSKH')} className={`px-4 py-1.5 rounded-lg text-[11px] font-black transition-all uppercase tracking-wider ${userRole === 'CSKH' ? 'bg-[#00a651] text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>CSKH</button>
              <button onClick={() => handleRoleSwitch('OSA')} className={`px-4 py-1.5 rounded-lg text-[11px] font-black transition-all uppercase tracking-wider ${userRole === 'OSA' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>OSA</button>
            </div>
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2 cursor-pointer hover:bg-slate-50 p-2 rounded-lg">
                <div className={`px-2 py-0.5 rounded text-[10px] font-black text-white ${userRole === 'CSKH' ? 'bg-emerald-600' : 'bg-indigo-600'}`}>{userRole}</div>
                <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center border-2 border-white shadow-sm overflow-hidden"><svg className="w-5 h-5 text-slate-400" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" /></svg></div>
                <div className="flex flex-col"><span className="text-[13px] font-bold text-slate-700 leading-none">{currentUser}</span></div>
              </div>
            </div>
          </div>
        </header>
        <div className="bg-[#00a651] px-6 py-2.5 flex items-center justify-between text-white text-[12px] font-medium shrink-0 shadow-sm">
          <div className="flex items-center gap-3">
            <div className="w-5 h-5 bg-white/20 rounded flex items-center justify-center"><svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 20 20"><path d="M10.707 2.293a1 1 0 00-1.414 0l-7 7a1 1 0 001.414 1.414L4 10.414V17a1 1 0 001 1h2a1 1 0 001-1v-2a1 1 0 011-1h2a1 1 0 011 1v2a1 1 0 001 1h2a1 1 0 001-1v-6.586l.293.293a1 1 0 001.414-1.414l-7-7z" /></svg></div>
            <span className="opacity-80">Trang chủ</span><span>&gt;</span><span className="opacity-80 uppercase font-bold">{getBreadcrumbs().parent}</span><span>&gt;</span><span className="font-bold uppercase">{getBreadcrumbs().page}</span>
          </div>
          <div className="flex items-center gap-4 text-[11px] font-bold">
            <div className="flex items-center gap-2"><span className={`px-2 py-0.5 rounded text-[9px] text-white ${userRole === 'CSKH' ? 'bg-emerald-700' : 'bg-indigo-700'}`}>{userRole}</span><span className="bg-white/10 px-2.5 py-1 rounded">{currentUser}</span></div>
            <span>{currentTime.split(' ')[0]}</span>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto scrollbar-thin">
          {currentView === 'ORDER_MANAGEMENT' && (
            <div className="p-4 space-y-4">
              <FilterPanel 
                filters={filters} 
                onFilterChange={handleFilterChange} 
                onSearch={applyFilters} 
                onMySupport={handleMySupport}
                onNotSupported={handleNotSupported}
                onClear={handleClearFilters}
                userRole={userRole}
              />
              <OrderTable 
                orders={filteredOrders} 
                onVerifyClick={handleOrderAction}
                onDetailClick={(order) => handleGoToDetail(order, false)} 
                currentUser={currentUser}
                userRole={userRole}
              />
            </div>
          )}
          {currentView === 'RESCUE_SUPERVISION' && <SupervisionDashboard orders={supervisionOrders} onAcceptSupport={(order) => setConfirmSupportOrder(order)} />}
          {currentView === 'ACTIVE_SUPPORT' && <ActiveSupportDashboard orders={supervisionOrders} onAcceptSupport={(order) => setConfirmSupportOrder(order)} />}
          {currentView === 'ORDER_DETAIL' && selectedOrderForDetail && (
            <OrderDetail 
              order={selectedOrderForDetail} 
              initialEditMode={detailEditMode}
              onBack={() => {
                setSelectedOrderForDetail(null);
                setCurrentView('ORDER_MANAGEMENT');
              }} 
              onSave={handleSaveOrder}
            />
          )}
        </div>
      </main>

      {/* Modals */}
      {selectedOrderForVerify && (
        <VerifyModal 
          order={selectedOrderForVerify} 
          onClose={() => setSelectedOrderForVerify(null)} 
          onConfirm={(status) => handleVerifyResult(selectedOrderForVerify.id, status)} 
        />
      )}

      {selectedOrderForSupport && (
        <SupportConfirmModal 
          order={{
            id: selectedOrderForSupport.id,
            orderCode: selectedOrderForSupport.orderCode,
            customerName: selectedOrderForSupport.customer.name,
            plate: selectedOrderForSupport.vehicle.plate,
            location: selectedOrderForSupport.address,
            services: selectedOrderForSupport.service,
            status: 'Searching',
            phone: selectedOrderForSupport.customer.phone,
            waitTime: '0p'
          }} 
          onClose={() => setSelectedOrderForSupport(null)} 
          onConfirm={() => handleAssignConfirm(selectedOrderForSupport.id, currentUser)} 
        />
      )}

      {selectedOrderForAssign && (
        <AssignModal
          order={selectedOrderForAssign}
          onClose={() => setSelectedOrderForAssign(null)}
          onConfirm={(userId) => handleAssignConfirm(selectedOrderForAssign.id, userId)}
          currentUser={currentUser}
        />
      )}

      {confirmSupportOrder && (
        <SupportConfirmModal 
          order={confirmSupportOrder} 
          onClose={() => setConfirmSupportOrder(null)} 
          onConfirm={() => handleAcceptSupportFromSupervision(confirmSupportOrder.id)} 
        />
      )}
    </div>
  );
};

export default App;
